  gr:{rule:'No verb conjugation — ever!',
    explain:'Indonesian verbs NEVER change form. "Saya makan" (I eat), "Dia makan" (She eats), "Mereka makan" (They eat) — the same verb every time. This makes Indonesian one of the easiest languages to start speaking immediately!',
    ex:[{id:'Saya baik.',en:'I am fine. (literally: I fine — no "am" needed!)'},{id:'Dia baik.',en:'She/He is fine. (same structure, different subject)'},{id:'Nama saya Ana.',en:'My name is Ana. (literally: name my Ana)'}]},
