  gr:{rule:'"Jam berapa sekarang?" — asking time without a verb',
    explain:'"Jam berapa?" = "What time?" (literally "hour how many?"). To tell time: "Sekarang jam [number]." Pattern for 11–19: [number] + belas. 20+: [tens] + puluh. No exceptions!',
    ex:[{id:'Jam berapa sekarang?',en:'What time is it now?'},{id:'Sekarang jam tiga sore.',en:'It is now 3 in the afternoon.'},{id:'Jam dua belas siang.',en:'12 noon exactly.'}]},
  build:{s:'Sekarang jam tiga.',e:'It is now 3 o\'clock.',w:['jam','Sekarang','tiga.','berapa','malam']},
  speak:{task:'Say 5 different times aloud, then describe what you do at each of those times.',dur:60,
    samples:[{id:'Sekarang jam tujuh pagi.',en:'It is now 7 in the morning.'},{id:'Jam dua belas siang saya makan.',en:'At noon I eat.'},{id:'Jam sembilan malam saya tidur.',en:'At 9pm I sleep.'},{id:'Setiap pagi saya bangun jam enam.',en:'Every morning I wake up at 6.'}]},
