    {id:'Mohon maaf',en:'I\'m terribly sorry (formal)',p:'moh-hon mah-af'},{id:'Tidak apa-apa',en:'It\'s okay / no problem',p:'tee-dak ah-pah ah-pah'},
    {id:'Sampai jumpa',en:'See you / goodbye',p:'sam-pie joom-pah'},{id:'Dengan senang hati',en:'With pleasure / gladly',p:'den-gan se-nang hah-tee'}
