const EXTRA = {
1:{dialogue:[{sp:'A',id:'Halo! Nama saya Budi. Siapa nama kamu?',en:'Hello! My name is Budi. What is your name?'},{sp:'B',id:'Halo Budi! Nama saya Siti. Senang bertemu!',en:'Hello Budi! My name is Siti. Nice to meet you!'},{sp:'A',id:'Senang bertemu juga, Siti! Apa kabar?',en:'Nice to meet you too, Siti! How are you?'},{sp:'B',id:'Kabar baik, terima kasih! Kamu dari mana?',en:'I\'m well, thank you! Where are you from?'},{sp:'A',id:'Saya dari Jakarta. Sampai jumpa!',en:'I\'m from Jakarta. See you again!'},{sp:'B',id:'Sampai jumpa! Hati-hati di jalan ya!',en:'See you! Take care on the road!'}],phrases:[{id:'Selamat datang!',en:'Welcome!',ctx:'When greeting someone arriving at your home or event'},{id:'Dengan senang hati.',en:'With pleasure / Gladly.',ctx:'A warm, polite way to say yes to a request'},{id:'Maaf, boleh saya tanya?',en:'Excuse me, may I ask?',ctx:'Polite way to start a question with a stranger'},{id:'Tidak masalah.',en:'No problem.',ctx:'Reassuring someone who apologised'},{id:'Saya tidak mengerti.',en:'I don\'t understand.',ctx:'When you need something repeated or explained'},{id:'Bisakah kamu bicara lebih pelan?',en:'Can you speak more slowly?',ctx:'Essential for learners — use freely!'},{id:'Tolong ulangi.',en:'Please repeat.',ctx:'Short and polite — use whenever needed'},{id:'Saya sedang belajar Bahasa Indonesia.',en:'I am learning Indonesian.',ctx:'People will immediately warm up and help you'}],reading:{text:'Nama saya Ana. Saya dari Australia. Saya belajar Bahasa Indonesia setiap hari. Bahasa Indonesia tidak terlalu sulit. Saya suka belajar bahasa baru!',translation:'My name is Ana. I am from Australia. I study Indonesian every day. Indonesian is not too difficult. I like learning new languages!',questions:[{q:'Siapa nama orang ini?',a:'Ana',hint:'Her name is in the first sentence'},{q:'Dari mana dia?',a:'Australia',hint:'From where? Second sentence'},{q:'Apakah Bahasa Indonesia sulit?',a:'Tidak, tidak terlalu sulit',hint:'The fourth sentence answers this'}]},exercises:[{type:'fill',prompt:'___ saya Ana. (My name is Ana)',ans:'Nama',hint:'The word for \'name\''},{type:'fill',prompt:'Apa ___? — Kabar baik! (How are you? — Fine!)',ans:'kabar',hint:'Part of the greeting \'apa kabar\''},{type:'order',words:['kasih','Terima','banyak'],ans:'Terima kasih banyak',en:'Thank you very much'},{type:'fill',prompt:'Senang ___ kamu! (Nice to meet you!)',ans:'bertemu',hint:'The verb \'to meet\''}]},
2:{dialogue:[{sp:'A',id:'Berapa umur kamu, Siti?',en:'How old are you, Siti?'},{sp:'B',id:'Saya dua puluh tiga tahun. Kamu?',en:'I am 23 years old. You?'},{sp:'A',id:'Saya dua puluh tahun. Kamu punya berapa saudara?',en:'I am 20. How many siblings do you have?'},{sp:'B',id:'Saya punya dua kakak dan satu adik. Jadi tiga!',en:'I have two older and one younger sibling. So three!'},{sp:'A',id:'Wah, banyak! Saya hanya satu adik.',en:'Wow, many! I have only one younger sibling.'},{sp:'B',id:'Iya, keluarga besar itu menyenangkan!',en:'Yes, a big family is enjoyable!'}],phrases:[{id:'Berapa umur kamu?',en:'How old are you?',ctx:'Common early question — always polite in Indonesian culture'},{id:'Saya... tahun.',en:'I am ... years old.',ctx:'Fill in the number — tahun = year'},{id:'Wah, benarkah?',en:'Wow, really?',ctx:'Showing genuine interest or surprise'},{id:'Saya tidak tahu.',en:'I don\'t know.',ctx:'Honest and perfectly natural to say'},{id:'Kami semua baik-baik saja.',en:'We are all doing well.',ctx:'Answering about a group — family or friends'},{id:'Hanya kami berdua.',en:'Just the two of us.',ctx:'berdua = the two of us, a useful compound'},{id:'Siapa dia?',en:'Who is that/he/she?',ctx:'Asking about someone — natural and polite'},{id:'Ini teman saya.',en:'This is my friend.',ctx:'Introducing someone next to you'}],reading:{text:'Saya punya keluarga kecil. Ada saya, ibu, bapak, dan satu adik. Adik saya berumur tujuh tahun. Dia lucu sekali! Kami tinggal di Bandung.',translation:'I have a small family. There is me, mother, father, and one younger sibling. My sibling is 7 years old. They are very cute! We live in Bandung.',questions:[{q:'Berapa orang di keluarga ini?',a:'Empat orang',hint:'Count the family members listed'},{q:'Berapa umur adiknya?',a:'Tujuh tahun',hint:'How old is the sibling?'},{q:'Di mana mereka tinggal?',a:'Bandung',hint:'Where do they live? Last sentence'}]},exercises:[{type:'fill',prompt:'Saya punya ___ saudara. (I have three siblings)',ans:'tiga',hint:'The number 3'},{type:'fill',prompt:'Berapa ___ kamu? — Saya dua puluh tahun.',ans:'umur',hint:'The word for \'age\''},{type:'order',words:['satu','Kami','ada','dan','dua'],ans:'Kami ada satu dan dua',en:'We have one and two (explaining family)'},{type:'fill',prompt:'___ kami bertiga. (There are three of us)',ans:'Kami',hint:'Subject meaning \'we\' (not including you)'}]},
3:{dialogue:[{sp:'A',id:'Budi, ini foto keluarga saya.',en:'Budi, this is a photo of my family.'},{sp:'B',id:'Oh, yang mana ibu kamu?',en:'Oh, which one is your mother?'},{sp:'A',id:'Ini ibu saya. Dia baik dan sabar sekali.',en:'This is my mother. She is very kind and patient.'},{sp:'B',id:'Wah, mirip kamu! Dan ini bapak kamu?',en:'Wow, you look alike! And is this your father?'},{sp:'A',id:'Iya, bapak saya guru. Dia suka baca buku.',en:'Yes, my father is a teacher. He likes reading books.'},{sp:'B',id:'Keluarga kamu kelihatan menyenangkan!',en:'Your family looks lovely!'}],phrases:[{id:'Ini foto keluarga saya.',en:'This is a photo of my family.',ctx:'Natural way to share a photo'},{id:'Dia mirip kamu!',en:'He/She looks like you!',ctx:'Commenting on family resemblance'},{id:'Bapak saya bekerja sebagai...',en:'My father works as a...',ctx:'Describing profession — sebagai = as/working as'},{id:'Ibu saya ibu rumah tangga.',en:'My mother is a homemaker.',ctx:'ibu rumah tangga literally = house tangga mother'},{id:'Kami tinggal bersama.',en:'We live together.',ctx:'tinggal = to live/reside, bersama = together'},{id:'Nenek saya masih sehat.',en:'My grandmother is still healthy.',ctx:'masih = still — very useful word'},{id:'Kami dekat sekali.',en:'We are very close.',ctx:'Describing a warm family relationship'},{id:'Sudah menikah?',en:'Are you married?',ctx:'Common question among adults — not considered rude in Indonesia'}],reading:{text:'Nama kakak saya Rina. Dia sudah menikah dan punya dua anak. Suaminya bernama Doni. Mereka tinggal di Surabaya. Setiap Lebaran, seluruh keluarga berkumpul di rumah nenek.',translation:'My older sibling\'s name is Rina. She is already married and has two children. Her husband\'s name is Doni. They live in Surabaya. Every Eid, the whole family gathers at grandma\'s house.',questions:[{q:'Siapa nama kakaknya?',a:'Rina',hint:'Name is in the first sentence'},{q:'Di mana Rina dan Doni tinggal?',a:'Surabaya',hint:'Where do they live?'},{q:'Kapan seluruh keluarga berkumpul?',a:'Setiap Lebaran',hint:'Every... what occasion?'}]},exercises:[{type:'fill',prompt:'___ saya bernama Rina. (My older sibling\'s name is Rina)',ans:'Kakak',hint:'Older sibling'},{type:'fill',prompt:'Dia sudah ___. (She is already married)',ans:'menikah',hint:'The verb \'to be married\''},{type:'order',words:['tinggal','Mereka','Surabaya','di'],ans:'Mereka tinggal di Surabaya',en:'They live in Surabaya'},{type:'fill',prompt:'Ibu saya ___ dan sabar. (My mother is kind and patient)',ans:'baik',hint:'The adjective meaning \'kind/good\''}]},
4:{dialogue:[{sp:'A',id:'Siti, tas kamu bagus sekali! Warnanya apa?',en:'Siti, your bag is very nice! What color is it?'},{sp:'B',id:'Terima kasih! Ini biru tua. Kamu suka warna apa?',en:'Thank you! This is dark blue. What color do you like?'},{sp:'A',id:'Saya suka hijau. Sepatu kamu juga baru ya?',en:'I like green. Your shoes are also new, right?'},{sp:'B',id:'Iya! Saya beli kemarin. Harganya murah sekali.',en:'Yes! I bought them yesterday. The price was very cheap.'},{sp:'A',id:'Wah, di mana kamu belinya?',en:'Wow, where did you buy them?'},{sp:'B',id:'Di pasar tradisional dekat rumah saya.',en:'At the traditional market near my house.'}],phrases:[{id:'Warna apa ini?',en:'What color is this?',ctx:'Asking about a color you don\'t know'},{id:'Saya suka warna...',en:'I like the color...',ctx:'Expressing color preference'},{id:'Ini baru atau lama?',en:'Is this new or old?',ctx:'Asking about condition of an object'},{id:'Ada warna lain?',en:'Is there another color?',ctx:'Shopping question — when you want options'},{id:'Yang mana yang kamu mau?',en:'Which one do you want?',ctx:'Helping someone choose — yang mana = which one'},{id:'Boleh saya lihat?',en:'May I see/look?',ctx:'Asking to examine something — very common when shopping'},{id:'Ini terlalu besar/kecil.',en:'This is too big/small.',ctx:'Essential for shopping — terlalu = too (much)'},{id:'Apakah ada ukuran yang lebih kecil?',en:'Is there a smaller size?',ctx:'Asking for a different size'}],reading:{text:'Kamar saya tidak terlalu besar. Ada meja coklat, kursi hitam, dan lemari biru. Di atas meja ada buku merah dan tas hijau saya. Jendela kamar saya menghadap taman yang indah.',translation:'My room is not too big. There is a brown table, black chair, and blue wardrobe. On the table is my red book and green bag. My room\'s window faces a beautiful garden.',questions:[{q:'Apa warna mejanya?',a:'Coklat',hint:'Color of the table'},{q:'Ada apa di atas meja?',a:'Buku merah dan tas hijau',hint:'What is on top of the table?'},{q:'Ke mana jendela kamar menghadap?',a:'Ke taman yang indah',hint:'What does the window face?'}]},exercises:[{type:'fill',prompt:'Tas ___ saya. (My blue bag — adjective after noun!)',ans:'biru',hint:'The color blue'},{type:'fill',prompt:'Ini ___ besar, ada yang lebih kecil? (This is too big, is there a smaller one?)',ans:'terlalu',hint:'The word meaning \'too (much)\''},{type:'order',words:['meja','di','buku','atas','Ada'],ans:'Ada buku di atas meja',en:'There is a book on the table'},{type:'fill',prompt:'Boleh saya ___? (May I see/look?)',ans:'lihat',hint:'The verb \'to see/look\''}]},
5:{dialogue:[{sp:'A',id:'Jam berapa sekarang, Budi?',en:'What time is it now, Budi?'},{sp:'B',id:'Sekarang jam sembilan kurang lima menit.',en:'It\'s now five minutes to nine.'},{sp:'A',id:'Aduh, saya terlambat! Kelas mulai jam sembilan.',en:'Oh no, I\'m late! Class starts at nine.'},{sp:'B',id:'Tenang saja, dari sini hanya lima menit jalan kaki.',en:'Don\'t worry, from here it\'s only five minutes on foot.'},{sp:'A',id:'Oke! Kita bertemu jam dua belas siang ya?',en:'Okay! We meet at 12 noon, right?'},{sp:'B',id:'Iya, di kantin. Jangan terlambat lagi!',en:'Yes, at the canteen. Don\'t be late again!'}],phrases:[{id:'Jam berapa kelas mulai?',en:'What time does class start?',ctx:'mulai = to start/begin'},{id:'Saya terlambat!',en:'I am late!',ctx:'terlambat = late — very useful to know!'},{id:'Masih lama?',en:'Is it much longer? / Is there still a long wait?',ctx:'Asking how much time remains'},{id:'Sebentar lagi.',en:'Just a little longer / In a moment.',ctx:'Reassuring someone it won\'t take long'},{id:'Tepat waktu.',en:'On time / Punctual.',ctx:'Complimenting or confirming punctuality'},{id:'Kita janjian jam berapa?',en:'What time do we have an appointment?',ctx:'janjian = to make an appointment/plan to meet'},{id:'Saya tunggu kamu di sini.',en:'I\'ll wait for you here.',ctx:'tunggu = to wait — very common'},{id:'Sudah hampir tiba.',en:'Almost arrived / Almost there.',ctx:'Texting someone you\'re nearly there'}],reading:{text:'Jadwal harian saya sangat padat. Saya bangun jam lima pagi dan mandi. Jam enam saya sarapan bersama keluarga. Jam tujuh saya berangkat ke kantor. Saya pulang ke rumah jam enam sore. Malam hari, saya belajar Bahasa Indonesia selama satu jam.',translation:'My daily schedule is very packed. I wake up at 5am and shower. At 6 I have breakfast with family. At 7 I leave for the office. I return home at 6pm. In the evening, I study Indonesian for one hour.',questions:[{q:'Jam berapa dia bangun?',a:'Jam lima pagi',hint:'When does he/she wake up?'},{q:'Jam berapa dia berangkat ke kantor?',a:'Jam tujuh',hint:'When does he/she leave for the office?'},{q:'Apa yang dia lakukan di malam hari?',a:'Belajar Bahasa Indonesia',hint:'What does he/she do in the evening?'}]},exercises:[{type:'fill',prompt:'Jam ___ sekarang? (What time is it now?)',ans:'berapa',hint:'The question word for numbers'},{type:'fill',prompt:'Saya ___ ke kantor jam tujuh. (I leave for the office at 7)',ans:'berangkat',hint:'The verb \'to depart/leave\''},{type:'order',words:['pagi','lima','Jam','saya','bangun'],ans:'Jam lima saya bangun pagi',en:'At five I wake up in the morning'},{type:'fill',prompt:'Kita ___ jam dua belas ya? (We meet at 12, right?)',ans:'bertemu',hint:'The verb \'to meet\''}]},
6:{dialogue:[{sp:'A',id:'Halo Siti! Sudah lama tidak bertemu.',en:'Hello Siti! Long time no see.'},{sp:'B',id:'Iya! Apa kabar? Kamu kelihatan sehat.',en:'Yes! How are you? You look healthy.'},{sp:'A',id:'Baik sekali, terima kasih! Kamu sendiri bagaimana?',en:'Very well, thank you! How about yourself?'},{sp:'B',id:'Saya juga baik. Lagi sibuk dengan pekerjaan.',en:'I\'m fine too. Quite busy with work.'},{sp:'A',id:'Oh ya? Kamu kerja di mana sekarang?',en:'Oh really? Where do you work now?'},{sp:'B',id:'Saya masih di perusahaan yang sama. Sudah tiga tahun!',en:'I\'m still at the same company. Already three years!'}],phrases:[{id:'Sudah lama tidak bertemu!',en:'Long time no see!',ctx:'Warm greeting for someone you haven\'t seen in a while'},{id:'Kamu kelihatan sehat/baik.',en:'You look healthy/well.',ctx:'A warm compliment about someone\'s appearance'},{id:'Masih ingat saya?',en:'Do you still remember me?',ctx:'When meeting someone you haven\'t seen in years'},{id:'Kita harus jalan-jalan bareng!',en:'We should hang out together!',ctx:'jalan-jalan = to stroll/go around, bareng = together'},{id:'Kapan-kapan ya!',en:'Some time soon! (casual)',ctx:'A warm but non-committal plan to meet — very Indonesian'},{id:'Salam untuk keluarga ya.',en:'Regards to your family.',ctx:'A warm way to end a conversation'},{id:'Hati-hati di jalan.',en:'Take care on the road / Be safe.',ctx:'Standard goodbye — shows genuine care'},{id:'Sampai ketemu lagi!',en:'Until we meet again!',ctx:'Warmer and more personal than sampai jumpa'}],reading:{text:'Budi dan Siti bertemu di kafe. Mereka sudah lama tidak bertemu. Budi memesan kopi hitam, dan Siti memesan teh manis. Mereka berbicara tentang pekerjaan dan keluarga. Waktu berlalu sangat cepat. Sebelum pulang, mereka berfoto bersama.',translation:'Budi and Siti meet at a café. They haven\'t met in a long time. Budi orders black coffee, and Siti orders sweet tea. They talk about work and family. Time passes very quickly. Before going home, they take a photo together.',questions:[{q:'Di mana Budi dan Siti bertemu?',a:'Di kafe',hint:'Where do they meet?'},{q:'Apa yang Budi pesan?',a:'Kopi hitam',hint:'What does Budi order?'},{q:'Apa yang mereka lakukan sebelum pulang?',a:'Berfoto bersama',hint:'What do they do before going home?'}]},exercises:[{type:'fill',prompt:'Sudah lama tidak ___! (Long time no see!)',ans:'bertemu',hint:'The verb \'to meet\''},{type:'fill',prompt:'Kamu ___ sehat hari ini. (You look healthy today)',ans:'kelihatan',hint:'The verb \'to look/appear\''},{type:'order',words:['keluarga','untuk','Salam','ya'],ans:'Salam untuk keluarga ya',en:'Regards to the family'},{type:'fill',prompt:'Kapan-___! (Some time soon!)',ans:'kapan',hint:'Repeat the time word to make it casual'}]},
7:{dialogue:[{sp:'A',id:'Hari ini kamu mau ngapain, Siti?',en:'What are you going to do today, Siti?'},{sp:'B',id:'Saya mau santai di rumah. Mungkin dengar musik.',en:'I want to relax at home. Maybe listen to music.'},{sp:'A',id:'Lagu Indonesia apa yang kamu suka?',en:'What Indonesian songs do you like?'},{sp:'B',id:'Saya suka Hindia dan Tulus. Lagunya indah sekali.',en:'I like Hindia and Tulus. Their songs are so beautiful.'},{sp:'A',id:'Wah, selera kita sama! Saya juga suka mereka.',en:'Wow, we have the same taste! I like them too.'},{sp:'B',id:'Coba dengar lagu Tulus yang \'Gajah\'. Kamu pasti suka!',en:'Try listening to Tulus\'s song \'Gajah\'. You\'ll definitely like it!'}],phrases:[{id:'Hari ini mau ngapain?',en:'What are you going to do today?',ctx:'Casual — ngapain is informal contraction of \'mau apa\''},{id:'Saya mau bersantai.',en:'I want to relax.',ctx:'bersantai / santai = to relax — very Indonesian concept'},{id:'Tidak ada rencana khusus.',en:'No special plans.',ctx:'rencana = plan, khusus = special'},{id:'Coba dengarkan ini!',en:'Try listening to this!',ctx:'coba = try — encouraging someone gently'},{id:'Selera kita sama!',en:'We have the same taste!',ctx:'selera = taste/preference — great for bonding'},{id:'Aku suka banget lagu ini.',en:'I really love this song.',ctx:'Informal — suka banget = like very much'},{id:'Liriknya bagus sekali.',en:'The lyrics are so good.',ctx:'lirik = lyrics — common music discussion word'},{id:'Istirahat dulu ya.',en:'Rest first, okay.',ctx:'dulu = first, ya softens it — very natural'}],reading:{text:'Hari Minggu adalah hari favorit saya. Saya tidak bekerja dan bisa santai. Biasanya saya bangun lebih lambat dari biasa. Saya suka minum kopi sambil dengar musik. Kadang saya juga membaca buku atau jalan-jalan di taman. Hari Minggu membuat saya siap untuk minggu baru.',translation:'Sunday is my favourite day. I don\'t work and can relax. Usually I wake up later than usual. I like drinking coffee while listening to music. Sometimes I also read books or stroll in the park. Sunday makes me ready for the new week.',questions:[{q:'Hari apa yang favorit?',a:'Hari Minggu',hint:'Which day is the favourite?'},{q:'Apa yang dia lakukan sambil minum kopi?',a:'Dengar musik',hint:'What does he/she do while drinking coffee?'},{q:'Apa fungsi hari Minggu baginya?',a:'Membuat siap untuk minggu baru',hint:'What does Sunday do for him/her?'}]},exercises:[{type:'fill',prompt:'Hari ini saya mau ___. (Today I want to relax)',ans:'bersantai',hint:'The formal verb for \'to relax\''},{type:'fill',prompt:'Saya dengar musik ___ minum kopi. (I listen to music while drinking coffee)',ans:'sambil',hint:'The word meaning \'while/simultaneously\''},{type:'order',words:['sama!','kita','Selera'],ans:'Selera kita sama!',en:'We have the same taste!'},{type:'fill',prompt:'___ dulu ya! (Rest first!)',ans:'Istirahat',hint:'The verb \'to rest\''}]},
8:{dialogue:[{sp:'A',id:'Setiap hari kamu pergi ke mana?',en:'Where do you go every day?'},{sp:'B',id:'Saya pergi ke kantor. Saya bekerja sebagai akuntan.',en:'I go to the office. I work as an accountant.'},{sp:'A',id:'Naik apa kamu ke kantor?',en:'How do you get to the office?'},{sp:'B',id:'Saya naik kereta. Cepat dan tidak macet.',en:'I take the train. It\'s fast and not congested.'},{sp:'A',id:'Bagus! Saya naik ojek setiap hari. Lebih fleksibel.',en:'Nice! I take an ojek every day. More flexible.'},{sp:'B',id:'Iya, tapi hujan-hujanan dong kalau naik ojek!',en:'Yes, but you get rained on when riding an ojek!'}],phrases:[{id:'Saya bekerja sebagai...',en:'I work as a...',ctx:'sebagai = as (profession) — always use for job descriptions'},{id:'Jam kerja saya pukul... sampai...',en:'My working hours are ... to ...',ctx:'pukul = o\'clock (formal), sampai = until'},{id:'Macet parah hari ini.',en:'The traffic is very bad today.',ctx:'macet = traffic jam — an essential Jakarta word!'},{id:'Saya lembur hari ini.',en:'I\'m working overtime today.',ctx:'lembur = overtime — very common in Indonesian work culture'},{id:'Bos saya baik.',en:'My boss is nice.',ctx:'Simple but practical — bos is widely used'},{id:'Rapat jam berapa?',en:'What time is the meeting?',ctx:'rapat = meeting/gathering — key office word'},{id:'Saya kirim email dulu ya.',en:'Let me send the email first.',ctx:'kirim = to send — applies to email, messages, packages'},{id:'Selamat bekerja!',en:'Have a productive work day!',ctx:'A warm phrase said to someone starting work'}],reading:{text:'Hari kerja saya dimulai jam delapan pagi. Saya duduk di meja dan membuka komputer. Pagi hari biasanya untuk membaca email. Siang hari saya sering ada rapat dengan tim. Sore hari saya menyelesaikan laporan. Jam lima sore, saya pulang ke rumah.',translation:'My work day starts at 8am. I sit at my desk and open the computer. Mornings are usually for reading emails. During the day I often have meetings with the team. In the afternoon I finish reports. At 5pm, I go home.',questions:[{q:'Jam berapa hari kerja mulai?',a:'Jam delapan pagi',hint:'When does the work day begin?'},{q:'Apa yang dia lakukan di pagi hari?',a:'Membaca email',hint:'Morning activity'},{q:'Kapan dia pulang ke rumah?',a:'Jam lima sore',hint:'When does he/she go home?'}]},exercises:[{type:'fill',prompt:'Saya bekerja ___ dokter. (I work as a doctor)',ans:'sebagai',hint:'The word meaning \'as\' for professions'},{type:'fill',prompt:'Jakarta ___ parah setiap pagi. (Jakarta has bad traffic every morning)',ans:'macet',hint:'The word for traffic jam'},{type:'order',words:['kerja','berangkat','saya','ke','Jam','tujuh'],ans:'Jam tujuh saya berangkat ke kerja',en:'At seven I leave for work'},{type:'fill',prompt:'___ email dulu ya. (Let me send the email first)',ans:'Kirim',hint:'The verb \'to send\''}]},
9:{dialogue:[{sp:'A',id:'Permisi, ada nasi goreng?',en:'Excuse me, do you have fried rice?'},{sp:'B',id:'Ada! Mau pakai telur atau ayam?',en:'Yes! Do you want it with egg or chicken?'},{sp:'A',id:'Pakai ayam saja. Dan kurang pedas ya.',en:'With chicken please. And not too spicy.'},{sp:'B',id:'Oke, mau minum apa? Ada es teh dan air mineral.',en:'Okay, what would you like to drink? We have iced tea and mineral water.'},{sp:'A',id:'Es teh manis satu. Berapa harganya semua?',en:'One sweet iced tea. How much is everything?'},{sp:'B',id:'Dua puluh ribu rupiah saja, Kak.',en:'Just twenty thousand rupiah.'}],phrases:[{id:'Meja untuk berapa orang?',en:'Table for how many people?',ctx:'Standard first question at a restaurant'},{id:'Boleh lihat menunya?',en:'May I see the menu?',ctx:'Polite restaurant opener — use it every time'},{id:'Kurang pedas ya.',en:'Not too spicy, please.',ctx:'Essential for spice-sensitive visitors — kurang = less'},{id:'Tidak pakai... ya.',en:'Without..., please.',ctx:'Removing an ingredient — pakai = using/with'},{id:'Sudah termasuk...?',en:'Is ... already included?',ctx:'Asking if something is included in the price'},{id:'Minta bon / notanya.',en:'May I have the bill?',ctx:'bon or nota = bill/receipt — use either'},{id:'Enak sekali, saya tambah lagi!',en:'Very delicious, I\'ll have more!',ctx:'tambah = add/more — the highest compliment to a cook!'},{id:'Dibungkus ya.',en:'Wrapped up to go, please.',ctx:'bungkus = to wrap — ordering takeaway'}],reading:{text:'Warung Bu Tini terkenal di kampung kami. Dia masak nasi goreng, mie goreng, dan soto ayam. Harganya murah tapi rasanya enak sekali. Setiap pagi, banyak orang sarapan di sana. Saya suka memesan nasi goreng dengan telur mata sapi dan es teh manis.',translation:'Bu Tini\'s warung is famous in our village. She cooks fried rice, fried noodles, and chicken soto. The prices are cheap but the taste is delicious. Every morning, many people have breakfast there. I like to order fried rice with a sunny-side up egg and sweet iced tea.',questions:[{q:'Apa yang dijual di warung Bu Tini?',a:'Nasi goreng, mie goreng, dan soto ayam',hint:'What does she sell? Three items'},{q:'Bagaimana harga di warung Bu Tini?',a:'Murah',hint:'How are the prices?'},{q:'Apa pesanan favorit penulis?',a:'Nasi goreng dengan telur mata sapi dan es teh manis',hint:'What does the writer like to order?'}]},exercises:[{type:'fill',prompt:'Saya mau nasi goreng, ___ pedas ya. (I want fried rice, not too spicy)',ans:'kurang',hint:'The word meaning \'less/not enough\''},{type:'fill',prompt:'Boleh minta ___? (May I have the bill?)',ans:'bonnya',hint:'Bill/receipt + the suffix -nya'},{type:'order',words:['enak','banget','ini','Makanan'],ans:'Makanan ini enak banget',en:'This food is so delicious'},{type:'fill',prompt:'Saya mau ___ ya. (I want to take it to go)',ans:'dibungkus',hint:'Wrapped up to go'}]},
10:{dialogue:[{sp:'A',id:'Maaf, di mana halte bus terdekat?',en:'Excuse me, where is the nearest bus stop?'},{sp:'B',id:'Halte bus ada di seberang jalan itu.',en:'The bus stop is across that road.'},{sp:'A',id:'Bus nomor berapa yang ke stasiun?',en:'What bus number goes to the station?'},{sp:'B',id:'Naik bus nomor lima belas. Turun di simpang tiga.',en:'Take bus number 15. Get off at the T-junction.'},{sp:'A',id:'Berapa menit dari sini?',en:'How many minutes from here?'},{sp:'B',id:'Kira-kira dua puluh menit kalau tidak macet.',en:'Approximately 20 minutes if there\'s no traffic.'}],phrases:[{id:'Di mana halte bus terdekat?',en:'Where is the nearest bus stop?',ctx:'halte = bus stop, terdekat = nearest'},{id:'Naik yang mana?',en:'Which one do I take?',ctx:'Asking which bus/train/lane to use'},{id:'Turun di mana?',en:'Where do I get off?',ctx:'turun = to get off/descend — opposite of naik'},{id:'Berapa jauh dari sini?',en:'How far is it from here?',ctx:'Direct distance question'},{id:'Kira-kira berapa menit?',en:'Approximately how many minutes?',ctx:'kira-kira = approximately — use for estimates'},{id:'Salah jalan!',en:'Wrong way! / I took the wrong road!',ctx:'When you realise you\'re lost'},{id:'Tolong antar saya ke...',en:'Please take me to...',ctx:'Asking for a ride or to be taken somewhere'},{id:'Berhenti di sini saja.',en:'Stop here, please.',ctx:'Telling a driver to stop — in ojek, taxi, bus'}],reading:{text:'Transportasi di Jakarta sangat beragam. Ada bus TransJakarta, MRT, KRL, ojek, dan taksi. MRT adalah pilihan paling cepat untuk melintasi kota. Harganya mulai dari tiga ribu rupiah. Ojek online seperti Gojek sangat populer karena fleksibel. Banyak orang menggunakan aplikasi di ponsel untuk memesan ojek.',translation:'Transportation in Jakarta is very diverse. There is TransJakarta bus, MRT, KRL, ojek, and taxi. MRT is the fastest option for crossing the city. Prices start from three thousand rupiah. Online ojek like Gojek is very popular because it\'s flexible. Many people use apps on their phones to order ojek.',questions:[{q:'Apa transportasi tercepat di Jakarta?',a:'MRT',hint:'Fastest option for crossing the city'},{q:'Berapa harga MRT paling murah?',a:'Tiga ribu rupiah',hint:'Starting price'},{q:'Mengapa ojek online sangat populer?',a:'Karena fleksibel',hint:'Why is it popular?'}]},exercises:[{type:'fill',prompt:'___ di sini saja. (Stop here please)',ans:'Berhenti',hint:'The verb \'to stop\''},{type:'fill',prompt:'Berapa menit ___ sini? (How many minutes from here?)',ans:'dari',hint:'The preposition \'from\''},{type:'order',words:['stasiun','ke','bus','Naik','nomor','sepuluh'],ans:'Naik bus nomor sepuluh ke stasiun',en:'Take bus number ten to the station'},{type:'fill',prompt:'___ kira dua puluh menit. (Approximately 20 minutes)',ans:'Kira',hint:'First half of the word for \'approximately\''}]},
11:{dialogue:[{sp:'A',id:'Permisi, rumah sakit ada di mana?',en:'Excuse me, where is the hospital?'},{sp:'B',id:'Lurus terus, lalu belok kiri di lampu merah.',en:'Go straight ahead, then turn left at the traffic light.'},{sp:'A',id:'Jauh tidak dari sini?',en:'Is it far from here?'},{sp:'B',id:'Tidak terlalu jauh. Kira-kira sepuluh menit jalan kaki.',en:'Not too far. About ten minutes on foot.'},{sp:'A',id:'Terima kasih banyak, Pak!',en:'Thank you very much, sir!'},{sp:'B',id:'Sama-sama. Hati-hati ya, semoga cepat sembuh!',en:'You\'re welcome. Take care, hope you recover soon!'}],phrases:[{id:'Lurus terus sampai...',en:'Go straight until...',ctx:'lurus terus = keep going straight, very clear direction'},{id:'Di sebelah kiri/kanan...',en:'On the left/right side...',ctx:'Describing location relative to direction'},{id:'Tidak bisa lewat sini.',en:'You can\'t go through here.',ctx:'Being told about a blocked road or private property'},{id:'Ada jalan pintas?',en:'Is there a shortcut?',ctx:'jalan pintas = shortcut — useful when in a hurry'},{id:'Saya tersesat.',en:'I am lost.',ctx:'tersesat = lost (of direction) — important to know!'},{id:'Tolong tunjukkan di peta.',en:'Please show me on the map.',ctx:'tunjukkan = show, peta = map'},{id:'Dekat dengan...',en:'Near / Close to...',ctx:'Giving a landmark as reference point'},{id:'Semoga cepat sembuh!',en:'Hope you recover soon!',ctx:'Warm phrase for someone who is sick'}],reading:{text:'Kantor saya ada di pusat kota. Dari stasiun, saya harus berjalan kaki lima menit ke utara. Kemudian belok kanan di perempatan pertama. Gedung kantor saya berwarna biru dan sangat tinggi. Ada warung kopi tepat di sebelah pintu masuk. Saya selalu beli kopi di sana sebelum masuk kerja.',translation:'My office is in the city centre. From the station, I have to walk five minutes north. Then turn right at the first crossroads. My office building is blue and very tall. There is a coffee stall right next to the entrance. I always buy coffee there before going in to work.',questions:[{q:'Di mana letak kantor ini?',a:'Di pusat kota',hint:'Where is the office located?'},{q:'Apa warna gedung kantornya?',a:'Biru',hint:'What color is the building?'},{q:'Apa yang dia lakukan sebelum masuk kerja?',a:'Beli kopi',hint:'What does he/she do before entering work?'}]},exercises:[{type:'fill',prompt:'___ terus sampai lampu merah. (Go straight until the traffic light)',ans:'Lurus',hint:'The direction word for \'straight\''},{type:'fill',prompt:'Saya ___. Tolong bantu saya! (I am lost. Please help me!)',ans:'tersesat',hint:'The verb/adjective for being lost'},{type:'order',words:['kanan','Belok','pertama','di','perempatan'],ans:'Belok kanan di perempatan pertama',en:'Turn right at the first crossroads'},{type:'fill',prompt:'Kantornya ada di ___ kiri jalan. (The office is on the left side of the road)',ans:'sebelah',hint:'The word meaning \'side of\''}]},
12:{dialogue:[{sp:'A',id:'Budi, kamu biasanya bangun jam berapa?',en:'Budi, what time do you usually wake up?'},{sp:'B',id:'Saya bangun jam lima setiap pagi untuk sholat.',en:'I wake up at five every morning to pray.'},{sp:'A',id:'Wah, rajin! Saya susah bangun pagi.',en:'Wow, diligent! I have trouble waking up early.'},{sp:'B',id:'Haha, kebiasaan saja. Kamu sarapan apa tadi?',en:'Haha, just habit. What did you have for breakfast earlier?'},{sp:'A',id:'Saya sarapan roti dan telur. Cepat dan praktis.',en:'I had bread and egg. Quick and practical.'},{sp:'B',id:'Besok coba sarapan nasi uduk. Lebih mengenyangkan!',en:'Tomorrow try having nasi uduk for breakfast. More filling!'}],phrases:[{id:'Kamu biasanya ngapain pagi hari?',en:'What do you usually do in the morning?',ctx:'biasanya = usually — key routine word'},{id:'Saya sudah terbiasa.',en:'I\'m already used to it.',ctx:'terbiasa = accustomed to — about habits'},{id:'Susah bangun pagi.',en:'It\'s hard to wake up early.',ctx:'Very relatable! susah = difficult/hard'},{id:'Saya sarapan dulu ya.',en:'I\'ll have breakfast first.',ctx:'A natural morning phrase'},{id:'Hari ini hari apa?',en:'What day is it today?',ctx:'Simple but essential daily question'},{id:'Besok ada acara apa?',en:'What\'s happening tomorrow?',ctx:'acara = event/program — very useful social word'},{id:'Akhir pekan ini mau apa?',en:'What are you doing this weekend?',ctx:'akhir pekan = weekend — essential social phrase'},{id:'Semangat pagi!',en:'Good morning energy! / Rise and shine!',ctx:'Energetic morning greeting — very Indonesian spirit'}],reading:{text:'Rutinitas pagi saya selalu sama. Senin sampai Jumat, saya bangun jam enam. Saya mandi air dingin supaya segar. Kemudian saya berpakaian dan sarapan. Hari Sabtu dan Minggu adalah hari libur saya. Sabtu saya biasa ke pasar, dan Minggu saya istirahat di rumah.',translation:'My morning routine is always the same. Monday to Friday, I wake up at six. I shower with cold water to feel refreshed. Then I get dressed and have breakfast. Saturday and Sunday are my days off. On Saturday I usually go to the market, and Sunday I rest at home.',questions:[{q:'Jam berapa dia bangun hari kerja?',a:'Jam enam',hint:'What time on weekdays?'},{q:'Mengapa dia mandi air dingin?',a:'Supaya segar',hint:'Why cold water? supaya = so that'},{q:'Apa yang dia lakukan setiap Sabtu?',a:'Ke pasar',hint:'What does he/she do on Saturdays?'}]},exercises:[{type:'fill',prompt:'Saya ___ bangun pagi. (I\'m used to waking up early)',ans:'terbiasa',hint:'Accustomed to / used to'},{type:'fill',prompt:'___ ini hari apa? (What day is it today?)',ans:'Hari',hint:'The word for \'day\''},{type:'order',words:['Jumat','sampai','Senin','kerja','Hari'],ans:'Hari kerja Senin sampai Jumat',en:'Work days Monday to Friday'},{type:'fill',prompt:'Besok ada ___ apa? (What\'s happening tomorrow?)',ans:'acara',hint:'The word for event/program'}]},
13:{dialogue:[{sp:'A',id:'Siti, ini bukan tas kamu kan?',en:'Siti, this isn\'t your bag, is it?'},{sp:'B',id:'Bukan, itu bukan tas saya. Punya siapa ya?',en:'No, that\'s not my bag. Whose is it, I wonder?'},{sp:'A',id:'Tidak ada namanya. Isinya juga tidak jelas.',en:'There\'s no name on it. The contents are also unclear.'},{sp:'B',id:'Mungkin tas itu ketinggalan. Kita lapor ke keamanan.',en:'Maybe that bag was left behind. Let\'s report to security.'},{sp:'A',id:'Iya betul. Jangan sampai ada yang kehilangan.',en:'Yes that\'s right. We don\'t want anyone to lose it.'},{sp:'B',id:'Kamu baik sekali, selalu mau membantu orang lain!',en:'You\'re so kind, always wanting to help others!'}],phrases:[{id:'Ini bukan milik saya.',en:'This does not belong to me.',ctx:'milik = possession/belonging — important legal/polite word'},{id:'Saya tidak setuju.',en:'I disagree.',ctx:'Direct but polite way to disagree'},{id:'Itu bukan salah saya.',en:'That is not my fault.',ctx:'salah = wrong/mistake/fault'},{id:'Jangan khawatir.',en:'Don\'t worry.',ctx:'khawatir = worried — very common reassurance'},{id:'Tidak ada masalah.',en:'There is no problem.',ctx:'Stronger reassurance than \'tidak apa-apa\''},{id:'Saya belum siap.',en:'I\'m not ready yet.',ctx:'siap = ready — implies you will be ready soon'},{id:'Itu bukan urusan saya.',en:'That is not my business/concern.',ctx:'urusan = matter/affair — setting a boundary politely'},{id:'Jangan sampai terlambat ya!',en:'Make sure you\'re not late!',ctx:'Jangan sampai = make sure not to — strong reminder'}],reading:{text:'Kemarin saya tidak bisa pergi ke kantor. Saya tidak sakit, tapi mobil saya tidak bisa menyala. Saya sudah coba berkali-kali tapi tidak bisa. Akhirnya saya telepon mekanik. Mekanik bilang masalahnya bukan di mesin, tapi di aki. Untungnya aki baru tidak terlalu mahal.',translation:'Yesterday I couldn\'t go to the office. I wasn\'t sick, but my car wouldn\'t start. I tried many times but it wouldn\'t work. Finally I called a mechanic. The mechanic said the problem wasn\'t in the engine, but in the battery. Fortunately a new battery wasn\'t too expensive.',questions:[{q:'Mengapa dia tidak ke kantor kemarin?',a:'Karena mobilnya tidak bisa menyala',hint:'Why couldn\'t he/she go to the office?'},{q:'Apa masalah mobilnya?',a:'Akinya (baterai)',hint:'What was the car\'s problem?'},{q:'Apakah aki baru mahal?',a:'Tidak terlalu mahal',hint:'Was the new battery expensive?'}]},exercises:[{type:'fill',prompt:'Ini ___ milik saya. (This does not belong to me)',ans:'bukan',hint:'Not for nouns/identity'},{type:'fill',prompt:'Saya ___ siap. (I\'m not ready yet — but I will be)',ans:'belum',hint:'Not yet'},{type:'order',words:['khawatir','Jangan','ya!'],ans:'Jangan khawatir ya!',en:'Don\'t worry!'},{type:'fill',prompt:'___ ada masalah. (There is no problem)',ans:'Tidak',hint:'Negation for states/facts'}]},
14:{dialogue:[{sp:'A',id:'Sudah dua minggu kita belajar bareng ya!',en:'It\'s already been two weeks since we studied together!'},{sp:'B',id:'Iya! Kamu sudah bisa banyak ya sekarang.',en:'Yes! You can do a lot now.'},{sp:'A',id:'Masih banyak yang harus saya pelajari.',en:'There\'s still a lot I need to learn.'},{sp:'B',id:'Betul, tapi kamu sudah maju banyak. Bangga sama kamu!',en:'True, but you\'ve progressed a lot. I\'m proud of you!'},{sp:'A',id:'Terima kasih! Kamu guru yang baik sekali.',en:'Thank you! You are a very good teacher.'},{sp:'B',id:'Sama-sama! Terus semangat belajar ya!',en:'You\'re welcome! Keep up the enthusiasm for learning!'}],phrases:[{id:'Sudah dua minggu / bulan / tahun.',en:'It has already been two weeks/months/years.',ctx:'Expressing how long something has been going on'},{id:'Kamu sudah maju banyak!',en:'You\'ve progressed a lot!',ctx:'maju = to advance/progress — great encouragement'},{id:'Masih banyak yang harus dipelajari.',en:'There\'s still a lot to be learned.',ctx:'Humble acknowledgment of ongoing learning'},{id:'Saya bangga dengan diri saya.',en:'I am proud of myself.',ctx:'Healthy self-affirmation — bangga = proud'},{id:'Mari kita ulangi.',en:'Let\'s go over it again.',ctx:'ulangi = to repeat/review — learning context'},{id:'Saya tidak ingat.',en:'I don\'t remember.',ctx:'ingat = to remember — the opposite of lupa'},{id:'Bisa tolong jelaskan lagi?',en:'Could you please explain again?',ctx:'Polite way to ask for re-explanation'},{id:'Pelan-pelan saja.',en:'Just take it slow / One step at a time.',ctx:'Comforting phrase — pelan-pelan = slowly'}],reading:{text:'Dua minggu belajar Bahasa Indonesia membuat saya lebih percaya diri. Sekarang saya bisa menyapa orang, memesan makanan, dan bertanya arah. Masih banyak kata yang belum saya tahu. Tapi saya tidak khawatir karena saya belajar setiap hari. Perjalanan beribu mil dimulai dari satu langkah.',translation:'Two weeks of learning Indonesian has made me more confident. Now I can greet people, order food, and ask for directions. There are still many words I don\'t know yet. But I\'m not worried because I study every day. A journey of a thousand miles starts with a single step.',questions:[{q:'Apa yang membuat dia lebih percaya diri?',a:'Dua minggu belajar Bahasa Indonesia',hint:'What made him/her more confident?'},{q:'Apa yang dia sudah bisa lakukan?',a:'Menyapa orang, memesan makanan, dan bertanya arah',hint:'Three things listed'},{q:'Mengapa dia tidak khawatir?',a:'Karena dia belajar setiap hari',hint:'Why isn\'t he/she worried?'}]},exercises:[{type:'fill',prompt:'Kamu sudah ___ banyak! (You\'ve progressed a lot!)',ans:'maju',hint:'The verb/adjective meaning \'to advance/progress\''},{type:'fill',prompt:'Saya ___ bangga dengan kamu. (I\'m very proud of you)',ans:'sangat',hint:'The intensifier \'very\''},{type:'order',words:['saja','Pelan-pelan','ya!'],ans:'Pelan-pelan saja ya!',en:'Just take it slow!'},{type:'fill',prompt:'Bisa tolong ___ lagi? (Could you explain again?)',ans:'jelaskan',hint:'The verb \'to explain\''}]},
15:{dialogue:[{sp:'A',id:'Permisi Bu, berapa harga baju ini?',en:'Excuse me Ma\'am, how much is this shirt?'},{sp:'B',id:'Seratus lima puluh ribu, Kak.',en:'One hundred and fifty thousand, sis/bro.'},{sp:'A',id:'Wah, mahal sekali. Boleh kurang tidak?',en:'Wow, very expensive. Can you lower the price?'},{sp:'B',id:'Boleh, minimal seratus dua puluh ribu ya.',en:'Okay, minimum one hundred and twenty thousand.'},{sp:'A',id:'Seratus ribu saja ya Bu, saya ambil dua.',en:'Just one hundred thousand, Ma\'am, I\'ll take two.'},{sp:'B',id:'Oke deh! Karena kamu baik, saya kasih harga teman!',en:'Okay then! Because you\'re nice, I\'ll give you the friend price!'}],phrases:[{id:'Boleh saya coba dulu?',en:'May I try it on first?',ctx:'Essential before buying clothes or shoes'},{id:'Ada yang lebih murah?',en:'Is there something cheaper?',ctx:'Direct and polite — widely understood'},{id:'Saya ambil dua, boleh diskon?',en:'I\'ll take two, can I get a discount?',ctx:'Buying in bulk for a better price — common tactic'},{id:'Harga terbaik berapa?',en:'What is the best price?',ctx:'Cutting to the chase — harga terbaik = best price'},{id:'Bisa bayar pakai kartu?',en:'Can I pay by card?',ctx:'Increasingly common — not all warung accept card'},{id:'Ada kembalian?',en:'Do you have change?',ctx:'kembalian = change — important when paying with large bills'},{id:'Tolong bungkus yang bagus ya.',en:'Please wrap it nicely.',ctx:'When buying as a gift'},{id:'Ini asli atau KW?',en:'Is this genuine or fake?',ctx:'KW = knockoff — you\'ll hear this constantly at markets'}],reading:{text:'Pasar Tanah Abang di Jakarta adalah pasar tekstil terbesar di Asia Tenggara. Di sana ada ribuan kios yang menjual pakaian, kain, dan aksesoris. Harganya sangat terjangkau. Pengunjung bisa menawar harga dengan bebas. Setiap hari, ribuan orang datang berbelanja dari seluruh Indonesia bahkan dari luar negeri.',translation:'Tanah Abang Market in Jakarta is the largest textile market in Southeast Asia. There are thousands of stalls selling clothing, fabric, and accessories. The prices are very affordable. Visitors can bargain freely. Every day, thousands of people come to shop from all over Indonesia and even from abroad.',questions:[{q:'Di mana Pasar Tanah Abang?',a:'Jakarta',hint:'Which city?'},{q:'Apa yang dijual di pasar ini?',a:'Pakaian, kain, dan aksesoris',hint:'Three types of goods'},{q:'Dari mana saja pengunjung datang?',a:'Dari seluruh Indonesia bahkan luar negeri',hint:'Where do visitors come from?'}]},exercises:[{type:'fill',prompt:'Boleh saya ___ dulu? (May I try it on first?)',ans:'coba',hint:'The verb \'to try\''},{type:'fill',prompt:'Harga ___ berapa? (What is the best price?)',ans:'terbaik',hint:'The superlative adjective \'best\''},{type:'order',words:['diskon?','dua,','ambil','Saya','boleh'],ans:'Saya ambil dua, boleh diskon?',en:'I\'ll take two, can I get a discount?'},{type:'fill',prompt:'Bisa bayar pakai ___? (Can I pay by card?)',ans:'kartu',hint:'The word for card'}]},
16:{dialogue:[{sp:'A',id:'Mas, saya mau ke Monas. Tahu jalannya?',en:'Sir, I want to go to Monas. Do you know the way?'},{sp:'B',id:'Tahu! Bapak naik apa? Mau naik ojek?',en:'I know! How are you traveling, sir? Want to take an ojek?'},{sp:'A',id:'Iya, berapa ongkosnya?',en:'Yes, how much is the fare?'},{sp:'B',id:'Lima belas ribu saja, Pak. Sebentar sampai.',en:'Just fifteen thousand, sir. We\'ll arrive shortly.'},{sp:'A',id:'Oke, berangkat sekarang ya.',en:'Okay, let\'s leave now.'},{sp:'B',id:'Siap! Pegang ya Pak, jalannya agak ramai.',en:'Ready! Hold on sir, the road is a bit busy.'}],phrases:[{id:'Berapa ongkosnya?',en:'How much is the fare?',ctx:'ongkos = fare/cost of transport — always use this word'},{id:'Tolong percepat sedikit.',en:'Please go a little faster.',ctx:'percepat = to speed up — polite request'},{id:'Tolong perlambat, saya mabuk.',en:'Please slow down, I feel carsick.',ctx:'perlambat = to slow down, mabuk = drunk/nauseous'},{id:'Lewat jalan tol atau jalan biasa?',en:'Via toll road or regular road?',ctx:'tol = toll road — relevant across Indonesian cities'},{id:'Parkir di mana?',en:'Where do I park?',ctx:'parkir = parking — direct borrowing from English'},{id:'Saya mau turun di depan itu.',en:'I want to get off in front of that.',ctx:'turun di depan = get off in front of'},{id:'Kembalian buat kamu.',en:'Keep the change.',ctx:'Generous tip phrase — always appreciated'},{id:'Aman sampai tujuan!',en:'Safe arrival to your destination!',ctx:'A warm send-off phrase — tujuan = destination/goal'}],reading:{text:'Aplikasi Gojek mengubah cara orang bepergian di Indonesia. Dengan satu sentuhan di ponsel, kamu bisa memesan ojek, mobil, atau bahkan makanan. Drivernya ramah dan selalu membawa helm untuk penumpang. Harganya transparan — kamu tahu biaya sebelum berangkat. Gojek sekarang juga tersedia di beberapa negara Asia Tenggara.',translation:'The Gojek app has changed how people travel in Indonesia. With one tap on the phone, you can order a motorbike, car, or even food. The drivers are friendly and always bring a helmet for the passenger. The price is transparent — you know the cost before leaving. Gojek is now also available in several Southeast Asian countries.',questions:[{q:'Apa yang bisa kamu pesan lewat Gojek?',a:'Ojek, mobil, atau makanan',hint:'Three things you can order'},{q:'Mengapa harga Gojek transparan?',a:'Karena kamu tahu biaya sebelum berangkat',hint:'Why is it transparent?'},{q:'Di mana lagi Gojek tersedia selain Indonesia?',a:'Di beberapa negara Asia Tenggara',hint:'Where else is Gojek available?'}]},exercises:[{type:'fill',prompt:'___ ongkosnya ke stasiun? (How much is the fare to the station?)',ans:'Berapa',hint:'The question word for \'how much/many\''},{type:'fill',prompt:'Tolong ___ sedikit, saya terburu-buru. (Please speed up a little, I\'m in a hurry)',ans:'percepat',hint:'The verb \'to speed up\''},{type:'order',words:['tujuan','sampai','Aman'],ans:'Aman sampai tujuan',en:'Safe arrival to your destination'},{type:'fill',prompt:'Saya mau ___ di sini. (I want to get off here)',ans:'turun',hint:'The verb \'to get off/descend\''}]},
17:{dialogue:[{sp:'A',id:'Dokter, sudah dua hari saya sakit kepala.',en:'Doctor, I\'ve had a headache for two days.'},{sp:'B',id:'Apakah disertai demam atau mual?',en:'Is it accompanied by fever or nausea?'},{sp:'A',id:'Ada demam sedikit. Mual tidak ada.',en:'A slight fever. No nausea.'},{sp:'B',id:'Baik. Saya periksa dulu ya. Buka mulut kamu.',en:'Okay. Let me examine you first. Open your mouth.'},{sp:'A',id:'Dok, kira-kira sakit apa saya ini?',en:'Doctor, what illness do I have, approximately?'},{sp:'B',id:'Kemungkinan flu biasa. Istirahat dan minum banyak air.',en:'Likely just the common flu. Rest and drink plenty of water.'}],phrases:[{id:'Saya tidak enak badan.',en:'I don\'t feel well. / I feel unwell.',ctx:'tidak enak badan = literally body feels not good — very common phrase'},{id:'Sudah berapa lama?',en:'For how long has it been?',ctx:'Doctor asking duration — or anyone asking about a problem'},{id:'Tolong periksa saya.',en:'Please examine me.',ctx:'periksa = to examine/check — medical or general'},{id:'Saya alergi terhadap...',en:'I am allergic to...',ctx:'Essential medical phrase — terhadap = towards/to'},{id:'Apakah ada efek samping?',en:'Are there side effects?',ctx:'efek samping = side effects — important when given medicine'},{id:'Saya minta surat sakit.',en:'I need a sick note.',ctx:'surat sakit = sick letter/note — needed for work/school'},{id:'Semoga lekas sembuh!',en:'Get well soon!',ctx:'Warmer than \'semoga cepat sembuh\' — lekas = quickly'},{id:'Saya perlu istirahat.',en:'I need to rest.',ctx:'Essential self-care phrase'}],reading:{text:'Kesehatan adalah hal yang paling penting. Kita harus makan dengan teratur, tidur cukup, dan berolahraga. Di Indonesia, banyak orang memilih jamu sebagai obat tradisional. Jamu dibuat dari rempah-rempah alami seperti jahe, kunyit, dan temulawak. Banyak penelitian menunjukkan jamu memang bermanfaat bagi kesehatan.',translation:'Health is the most important thing. We must eat regularly, sleep enough, and exercise. In Indonesia, many people choose jamu as a traditional medicine. Jamu is made from natural spices like ginger, turmeric, and curcuma. Many studies show jamu is indeed beneficial for health.',questions:[{q:'Apa saja yang harus kita lakukan untuk sehat?',a:'Makan teratur, tidur cukup, dan berolahraga',hint:'Three healthy habits mentioned'},{q:'Apa itu jamu?',a:'Obat tradisional dari rempah-rempah alami',hint:'What is jamu?'},{q:'Apa saja bahan jamu yang disebutkan?',a:'Jahe, kunyit, dan temulawak',hint:'Three ingredients mentioned'}]},exercises:[{type:'fill',prompt:'Saya tidak ___ badan hari ini. (I don\'t feel well today)',ans:'enak',hint:'Part of the idiom for feeling unwell'},{type:'fill',prompt:'Saya ___ terhadap udang. (I am allergic to shrimp)',ans:'alergi',hint:'The word for allergy'},{type:'order',words:['sembuh!','lekas','Semoga'],ans:'Semoga lekas sembuh!',en:'Get well soon!'},{type:'fill',prompt:'Sudah berapa ___ kamu sakit? (How long have you been sick?)',ans:'lama',hint:'The word for \'long (time)\''}]},
18:{dialogue:[{sp:'A',id:'Wah, baju batik kamu bagus sekali!',en:'Wow, your batik shirt is very nice!'},{sp:'B',id:'Terima kasih! Ini batik dari Yogyakarta.',en:'Thank you! This is batik from Yogyakarta.'},{sp:'A',id:'Motifnya indah. Itu apa artinya?',en:'The pattern is beautiful. What does it mean?'},{sp:'B',id:'Motif ini namanya Parang. Melambangkan kekuatan.',en:'This pattern is called Parang. It symbolises strength.'},{sp:'A',id:'Kamu beli di sana langsung?',en:'Did you buy it there directly?'},{sp:'B',id:'Iya, waktu saya liburan ke Jogja bulan lalu.',en:'Yes, when I was on holiday in Jogja last month.'}],phrases:[{id:'Baju kamu keren banget!',en:'Your outfit is so cool!',ctx:'keren = cool/stylish — very common compliment'},{id:'Dari mana belinya?',en:'Where did you buy it?',ctx:'Very natural follow-up to a compliment'},{id:'Saya lagi cari baju kasual.',en:'I\'m looking for casual clothes.',ctx:'lagi = currently (doing) — essential informal word'},{id:'Ukurannya pas sekali.',en:'The size fits perfectly.',ctx:'pas = exactly right/fitting — also used for many contexts'},{id:'Ada yang cocok untuk acara formal?',en:'Is there something suitable for a formal event?',ctx:'cocok = suitable/matching — very versatile word'},{id:'Warnanya tidak pudar ya?',en:'The color won\'t fade, right?',ctx:'pudar = to fade — checking quality'},{id:'Boleh saya tukar kalau tidak cocok?',en:'Can I exchange it if it doesn\'t fit?',ctx:'tukar = to exchange — know your consumer rights!'},{id:'Ini hadiah untuk teman saya.',en:'This is a gift for my friend.',ctx:'hadiah = gift/present — common in Indonesian culture'}],reading:{text:'Batik adalah warisan budaya Indonesia yang diakui UNESCO. Setiap daerah di Indonesia memiliki corak batik yang berbeda. Batik Solo terkenal dengan warnanya yang halus. Batik Pekalongan lebih cerah dan berwarna-warni. Batik Madura menggunakan warna merah dan hitam yang kuat. Setiap motif batik memiliki filosofi dan makna tersendiri.',translation:'Batik is an Indonesian cultural heritage recognised by UNESCO. Every region in Indonesia has different batik patterns. Solo batik is famous for its subtle colors. Pekalongan batik is brighter and more colourful. Madura batik uses strong red and black colors. Every batik pattern has its own philosophy and meaning.',questions:[{q:'Siapa yang mengakui batik sebagai warisan budaya?',a:'UNESCO',hint:'Which organization recognised batik?'},{q:'Bagaimana ciri khas batik Solo?',a:'Warnanya halus',hint:'What are Solo batik colors like?'},{q:'Warna apa yang khas dari batik Madura?',a:'Merah dan hitam',hint:'What colors does Madura batik use?'}]},exercises:[{type:'fill',prompt:'Ukurannya ___ sekali! (The size fits perfectly!)',ans:'pas',hint:'The word meaning \'just right/fitting\''},{type:'fill',prompt:'Saya lagi ___ baju kasual. (I\'m currently looking for casual clothes)',ans:'cari',hint:'The verb \'to look for/search\''},{type:'order',words:['cocok?','tidak','Boleh','saya','tukar','kalau'],ans:'Boleh saya tukar kalau tidak cocok?',en:'Can I exchange it if it doesn\'t fit?'},{type:'fill',prompt:'Baju kamu ___ banget! (Your clothes are so cool!)',ans:'keren',hint:'The slang word for cool/stylish'}]},
19:{dialogue:[{sp:'A',id:'Hobi kamu apa, Budi?',en:'What is your hobby, Budi?'},{sp:'B',id:'Saya suka mendaki gunung. Kamu?',en:'I like mountain hiking. You?'},{sp:'A',id:'Wah, keren! Saya lebih suka hal yang santai. Membaca dan memasak.',en:'Wow, cool! I prefer relaxing things. Reading and cooking.'},{sp:'B',id:'Masak? Kamu bisa masak apa?',en:'Cooking? What can you cook?'},{sp:'A',id:'Saya bisa masak nasi goreng dan rendang. Tapi masih belajar!',en:'I can cook fried rice and rendang. But still learning!'},{sp:'B',id:'Keren! Nanti ajari saya masak rendang ya!',en:'Cool! Teach me how to cook rendang sometime!'}],phrases:[{id:'Saya hobi...',en:'My hobby is...',ctx:'Natural way to introduce a hobby'},{id:'Kamu tertarik dengan apa?',en:'What are you interested in?',ctx:'tertarik = interested in — deeper than just \'like\''},{id:'Saya ikut komunitas...',en:'I\'m part of a ... community.',ctx:'komunitas = community — Indonesians love community groups'},{id:'Ini pertama kali saya coba.',en:'This is the first time I\'ve tried this.',ctx:'Expressing a new experience'},{id:'Saya tidak berbakat di situ.',en:'I\'m not talented in that.',ctx:'berbakat = talented/gifted — humble expression'},{id:'Mau coba bareng?',en:'Want to try it together?',ctx:'Warm invitation to share an activity'},{id:'Kapan kita bisa latihan bareng?',en:'When can we practice together?',ctx:'latihan = to practice/train — sports and skills'},{id:'Saya sedang belajar...',en:'I am currently learning...',ctx:'Describing ongoing skill development'}],reading:{text:'Komunitas pendaki gunung di Indonesia sangat aktif. Setiap akhir pekan, ratusan orang mendaki gunung-gunung indah di seluruh Indonesia. Gunung Rinjani di Lombok dan Gunung Semeru di Jawa Timur adalah dua yang paling terkenal. Mendaki bukan hanya soal fisik, tapi juga soal mental dan kebersamaan. Banyak persahabatan sejati lahir di atas gunung.',translation:'The mountain hiking community in Indonesia is very active. Every weekend, hundreds of people hike the beautiful mountains across Indonesia. Mount Rinjani in Lombok and Mount Semeru in East Java are two of the most famous. Hiking is not just about physical fitness, but also mental strength and togetherness. Many genuine friendships are born on the mountain.',questions:[{q:'Di mana Gunung Rinjani?',a:'Di Lombok',hint:'Which island is Rinjani on?'},{q:'Mendaki gunung bukan hanya soal apa?',a:'Fisik saja',hint:'What is hiking NOT only about?'},{q:'Apa yang bisa lahir di atas gunung?',a:'Persahabatan sejati',hint:'What is born on the mountain?'}]},exercises:[{type:'fill',prompt:'Saya ___ dengan masak Indonesia. (I am interested in Indonesian cooking)',ans:'tertarik',hint:'The word meaning \'interested in\''},{type:'fill',prompt:'Ini pertama kali saya ___. (This is the first time I\'ve tried)',ans:'coba',hint:'The verb \'to try\''},{type:'order',words:['bareng?','latihan','kita','Kapan','bisa'],ans:'Kapan kita bisa latihan bareng?',en:'When can we practice together?'},{type:'fill',prompt:'Saya sedang ___ memasak. (I am currently learning to cook)',ans:'belajar',hint:'The verb \'to learn\''}]},
20:{dialogue:[{sp:'A',id:'Kamu sudah pernah ke Bali?',en:'Have you ever been to Bali?'},{sp:'B',id:'Sudah, dua kali! Bali indah sekali.',en:'Yes, twice! Bali is so beautiful.'},{sp:'A',id:'Tempat apa yang paling kamu suka di sana?',en:'What place do you like the most there?'},{sp:'B',id:'Saya paling suka Ubud. Seni dan budayanya luar biasa.',en:'I like Ubud the most. The art and culture is extraordinary.'},{sp:'A',id:'Iya, dan makanannya juga enak sekali!',en:'Yes, and the food there is also very delicious!'},{sp:'B',id:'Betul! Saya harap bisa balik lagi ke Bali tahun depan.',en:'True! I hope to return to Bali next year.'}],phrases:[{id:'Kapan terakhir kamu ke sana?',en:'When did you last go there?',ctx:'terakhir = last/most recent — time reference'},{id:'Wajib dikunjungi!',en:'A must-visit!',ctx:'wajib = obligatory, dikunjungi = to be visited'},{id:'Pemandangannya indah sekali.',en:'The scenery is so beautiful.',ctx:'pemandangan = scenery/view — travel essential'},{id:'Orang-orangnya ramah.',en:'The people are friendly.',ctx:'ramah = friendly/hospitable — often said about Indonesians'},{id:'Musim hujan atau musim kemarau?',en:'Rainy season or dry season?',ctx:'Indonesia has two seasons — crucial for travel planning'},{id:'Saya ingin balik lagi ke sana.',en:'I want to go back there again.',ctx:'balik = to return (informal) — very natural'},{id:'Tempat apa yang direkomendasikan?',en:'What place is recommended?',ctx:'direkomendasikan = recommended — asking for tips'},{id:'Budayanya sangat kaya.',en:'The culture is very rich.',ctx:'kaya = rich (culture, flavour, colour — not just money)'}],reading:{text:'Indonesia terdiri dari lebih dari 17.000 pulau. Di antara pulau-pulau itu, ada Sumatra, Jawa, Kalimantan, Sulawesi, dan Papua yang termasuk pulau terbesar. Setiap pulau memiliki bahasa daerah, budaya, dan masakan khasnya sendiri. Inilah keunikan Indonesia yang membuat dunia kagum. Bhinneka Tunggal Ika benar-benar hidup di sini.',translation:'Indonesia consists of more than 17,000 islands. Among those islands, Sumatra, Java, Kalimantan, Sulawesi, and Papua are among the largest. Each island has its own regional language, culture, and signature cuisine. This is the uniqueness of Indonesia that amazes the world. Unity in Diversity truly lives here.',questions:[{q:'Berapa jumlah pulau di Indonesia?',a:'Lebih dari 17.000',hint:'How many islands?'},{q:'Sebutkan tiga pulau terbesar di Indonesia!',a:'Sumatra, Jawa, Kalimantan (dll)',hint:'Name three of the large islands'},{q:'Apa yang dimaksud \'Bhinneka Tunggal Ika\'?',a:'Unity in Diversity / Berbeda-beda tapi tetap satu',hint:'The national motto\'s meaning'}]},exercises:[{type:'fill',prompt:'Pemandangannya ___ sekali! (The scenery is so beautiful!)',ans:'indah',hint:'The adjective for beautiful'},{type:'fill',prompt:'Bali ___ dikunjungi! (Bali is a must-visit!)',ans:'wajib',hint:'The word for obligatory/must'},{type:'order',words:['ke','balik','lagi','sana','Saya','ingin'],ans:'Saya ingin balik lagi ke sana',en:'I want to go back there again'},{type:'fill',prompt:'Budayanya sangat ___. (The culture is very rich)',ans:'kaya',hint:'The word for \'rich\' (in culture, flavour etc)'}]},
21:{dialogue:[{sp:'A',id:'Selamat pagi semua! Ini vlog saya dari Jakarta!',en:'Good morning everyone! This is my vlog from Jakarta!'},{sp:'B',id:'Halo! Saya sedang di Pasar Baru. Ramai sekali!',en:'Hello! I\'m currently at Pasar Baru. Very busy!'},{sp:'A',id:'Saya baru saja naik MRT dari Lebak Bulus.',en:'I just took the MRT from Lebak Bulus.'},{sp:'B',id:'Cepat ya? Dulu macet banget di sini.',en:'It\'s fast, right? It used to be very congested here.'},{sp:'A',id:'Iya, Jakarta terus berkembang. Kota yang luar biasa!',en:'Yes, Jakarta keeps developing. An extraordinary city!'},{sp:'B',id:'Setuju! Kalau ke Jakarta lagi, harus coba kuliner lokalnya!',en:'Agreed! If you come to Jakarta again, must try the local food!'}],phrases:[{id:'Saya baru saja tiba.',en:'I just arrived.',ctx:'baru saja = just (did something) — very useful expression'},{id:'Ramai sekali di sini!',en:'It\'s very crowded here!',ctx:'ramai = crowded/busy/lively — not negative, often positive'},{id:'Kota ini terus berkembang.',en:'This city keeps developing.',ctx:'berkembang = to develop/grow — useful for describing progress'},{id:'Wajib coba kuliner lokalnya!',en:'Must try the local food!',ctx:'kuliner = culinary/food scene — borrowed from French'},{id:'Sudah berapa lama di sini?',en:'How long have you been here?',ctx:'Asking someone about their stay or visit duration'},{id:'Ada tempat yang direkomendasikan?',en:'Are there any recommended places?',ctx:'Asking for local tips — very common travel question'},{id:'Saya jatuh cinta dengan kota ini.',en:'I fell in love with this city.',ctx:'jatuh cinta = fall in love — used for places, food, people!'},{id:'Sampai jumpa di video berikutnya!',en:'See you in the next video!',ctx:'Classic vlogger sign-off — berikutnya = next'}],reading:{text:'Jakarta adalah ibu kota Indonesia sekaligus kota terbesar. Populasinya lebih dari sepuluh juta jiwa di dalam kota, dan tiga puluh juta di area metropolitannya. Jakarta terkenal dengan kemacetan lalu lintasnya, tapi juga dengan kuliner, seni, dan kehidupan malam yang semarak. Saat ini pemerintah sedang memindahkan ibu kota ke Nusantara di Kalimantan.',translation:'Jakarta is Indonesia\'s capital as well as the largest city. Its population is more than ten million within the city, and thirty million in its metropolitan area. Jakarta is famous for its traffic congestion, but also for its food, arts, and vibrant nightlife. Currently the government is moving the capital to Nusantara in Kalimantan.',questions:[{q:'Berapa populasi Jakarta di dalam kota?',a:'Lebih dari sepuluh juta jiwa',hint:'Population within the city'},{q:'Apa yang membuat Jakarta terkenal?',a:'Kemacetan, kuliner, seni, dan kehidupan malam',hint:'Multiple things — name at least two'},{q:'Ke mana ibu kota Indonesia dipindahkan?',a:'Ke Nusantara di Kalimantan',hint:'New capital name and location'}]},exercises:[{type:'fill',prompt:'Saya baru saja ___. (I just arrived)',ans:'tiba',hint:'The formal verb \'to arrive\''},{type:'fill',prompt:'___ sekali di sini! (It\'s very crowded here!)',ans:'Ramai',hint:'The word for crowded/lively'},{type:'order',words:['ini','kota','Saya','dengan','jatuh','cinta'],ans:'Saya jatuh cinta dengan kota ini',en:'I fell in love with this city'},{type:'fill',prompt:'Wajib coba ___ lokalnya! (Must try the local food!)',ans:'kuliner',hint:'The word for culinary/local food scene'}]},
22:{dialogue:[{sp:'A',id:'Bud, lo udah makan belum?',en:'Bud, have you eaten yet? (informal)'},{sp:'B',id:'Belum nih. Lo mau ngajak makan?',en:'Not yet. Are you inviting me to eat?'},{sp:'A',id:'Iya dong! Tapi gue gak tau mau makan apa.',en:'Yeah of course! But I don\'t know what to eat.'},{sp:'B',id:'Gimana kalau soto? Gue tau warung yang enak banget.',en:'How about soto? I know a really good warung.'},{sp:'A',id:'Sip! Tapi jauh gak? Gue lagi males jalan jauh.',en:'Cool! But is it far? I\'m feeling lazy to walk far.'},{sp:'B',id:'Deket kok! Lima menit doang. Yuk berangkat!',en:'It\'s close! Only five minutes. Let\'s go!'}],phrases:[{id:'Lo udah makan?',en:'Have you eaten? (informal)',ctx:'lo = you (informal Jakarta slang), udah = already'},{id:'Gue gak tau.',en:'I don\'t know. (informal)',ctx:'gue = I/me (informal) — heard constantly in Jakarta'},{id:'Gimana kalau...?',en:'How about...? / What if...?',ctx:'Suggesting an idea casually'},{id:'Yuk berangkat!',en:'Let\'s go! / Let\'s head off!',ctx:'yuk = come on, let\'s — very energetic and casual'},{id:'Capek banget nih.',en:'I\'m so tired.',ctx:'nih = informal \'this/here\', adds emphasis to feelings'},{id:'Santai aja.',en:'Just relax / Chill out.',ctx:'aja = just/only (informal shortening of saja)'},{id:'Beneran?',en:'Really? / For real?',ctx:'beneran = informal of \'benaran\' — expressing surprise'},{id:'Makasih ya!',en:'Thanks! (informal)',ctx:'Makasih = informal shortening of terima kasih'}],reading:{text:'Bahasa gaul adalah bahasa informal yang digunakan anak muda Indonesia, terutama di Jakarta. Beberapa kata gaul yang populer antara lain: \'gue\' (saya), \'lo\' (kamu), \'bokap\' (ayah), dan \'nyokap\' (ibu). Bahasa gaul terus berubah dan berkembang mengikuti tren. Media sosial mempercepat penyebaran kata-kata baru. Meski tidak formal, memahami bahasa gaul sangat membantu saat bergaul dengan anak muda Indonesia.',translation:'Bahasa gaul is the informal language used by young Indonesians, especially in Jakarta. Some popular slang words include: \'gue\' (I), \'lo\' (you), \'bokap\' (father), and \'nyokap\' (mother). Slang keeps changing and evolving with trends. Social media accelerates the spread of new words. Although not formal, understanding slang is very helpful when socialising with young Indonesians.',questions:[{q:'Apa itu bahasa gaul?',a:'Bahasa informal anak muda Indonesia',hint:'What is bahasa gaul?'},{q:'Apa arti kata \'bokap\'?',a:'Ayah (father)',hint:'What does \'bokap\' mean?'},{q:'Apa yang mempercepat penyebaran bahasa gaul?',a:'Media sosial',hint:'What accelerates the spread?'}]},exercises:[{type:'fill',prompt:'Lo udah ___ belum? (Have you eaten yet? — informal)',ans:'makan',hint:'The verb \'to eat\''},{type:'fill',prompt:'___ kalau kita makan soto? (How about we eat soto?)',ans:'Gimana',hint:'Informal \'how about\''},{type:'order',words:['Yuk','berangkat!'],ans:'Yuk berangkat!',en:'Let\'s go!'},{type:'fill',prompt:'Santai ___ ya! (Just relax!)',ans:'aja',hint:'Informal shortening of \'saja\''}]},
23:{dialogue:[{sp:'A',id:'Aduh, udah jam segini lah!',en:'Oh no, it\'s already this late!'},{sp:'B',id:'Iya sih, tapi kita masih bisa kejar dong!',en:'Yeah, but we can still make it, right!'},{sp:'A',id:'Gimana caranya? Macet banget nih di mana-mana.',en:'How? It\'s so congested everywhere.'},{sp:'B',id:'Naik ojek aja! Bisa selip-selip.',en:'Just take an ojek! Can weave through traffic.'},{sp:'A',id:'Oke deh! Lo pesen dulu ya, gue gak ada pulsa.',en:'Okay then! You order first, I don\'t have data credit.'},{sp:'B',id:'Siap! Udah gue pesen nih. Lima menit lagi sampai.',en:'Done! I\'ve ordered it. Five more minutes and it arrives.'}],phrases:[{id:'Udah lah!',en:'Come on! / Just get on with it! / Enough!',ctx:'Expressing mild frustration or urging action'},{id:'Iya sih, tapi...',en:'Yes, but... (acknowledging then disagreeing)',ctx:'Soft way to push back — very common in conversation'},{id:'Bisa kejar kok!',en:'We can make it!',ctx:'kejar = to chase/catch up with — used for time and targets'},{id:'Di mana-mana macet.',en:'There\'s traffic everywhere.',ctx:'di mana-mana = everywhere — strong exaggeration phrase'},{id:'Sabar dong!',en:'Be patient, please!',ctx:'sabar = patient — combined with dong for a soft plea'},{id:'Hampir sampai nih!',en:'Almost there!',ctx:'nih adds informal immediacy — \'like, almost there!\''},{id:'Gak usah buru-buru.',en:'No need to rush.',ctx:'buru-buru = to rush/hurry — gak usah = no need to'},{id:'Santai, masih ada waktu.',en:'Relax, there\'s still time.',ctx:'Reassuring phrase when someone is stressed about time'}],reading:{text:'Dalam percakapan sehari-hari, orang Indonesia sering menggunakan partikel \'lah\', \'dong\', \'sih\', dan \'kan\'. Partikel-partikel ini tidak ada padanannya langsung dalam Bahasa Inggris. \'Lah\' biasanya memperlunak perintah. \'Dong\' membuat permintaan terdengar lebih ramah. \'Sih\' mengekspresikan keheranan atau sedikit frustrasi. \'Kan\' mencari konfirmasi dari lawan bicara. Menguasai partikel ini adalah kunci berbicara seperti penutur asli.',translation:'In daily conversation, Indonesians often use the particles \'lah\', \'dong\', \'sih\', and \'kan\'. These particles have no direct English equivalent. \'Lah\' usually softens a command. \'Dong\' makes a request sound friendlier. \'Sih\' expresses wonder or slight frustration. \'Kan\' seeks confirmation from the conversation partner. Mastering these particles is the key to speaking like a native.',questions:[{q:'Apa fungsi partikel \'lah\'?',a:'Memperlunak perintah',hint:'What does \'lah\' do?'},{q:'Partikel mana yang mencari konfirmasi?',a:'\'Kan\'',hint:'Which particle seeks confirmation?'},{q:'Mengapa partikel penting untuk dipelajari?',a:'Kunci berbicara seperti penutur asli',hint:'Why are particles important?'}]},exercises:[{type:'fill',prompt:'Sabar ___ ya! (Be patient, please!)',ans:'dong',hint:'The particle that softens a request'},{type:'fill',prompt:'Di mana-___ macet hari ini! (Traffic is everywhere today!)',ans:'mana',hint:'Second part of \'everywhere\''},{type:'order',words:['masih','waktu','ada','Santai,'],ans:'Santai, masih ada waktu',en:'Relax, there\'s still time'},{type:'fill',prompt:'Hampir ___ nih! (Almost there!)',ans:'sampai',hint:'The verb \'to arrive\''}]},
24:{dialogue:[{sp:'A',id:'Tadi malam saya mimpi aneh banget.',en:'Last night I had a very strange dream.'},{sp:'B',id:'Mimpi apa? Cerita dong!',en:'What dream? Tell me!'},{sp:'A',id:'Pertama saya ada di hutan. Tiba-tiba ada harimau!',en:'First I was in a forest. Suddenly there was a tiger!'},{sp:'B',id:'Aduh! Lalu apa yang terjadi?',en:'Oh no! Then what happened?'},{sp:'A',id:'Saya lari kencang sekali. Akhirnya saya terbangun.',en:'I ran very fast. In the end I woke up.'},{sp:'B',id:'Hahaha! Untungnya cuma mimpi. Kamu baik-baik saja kan?',en:'Hahaha! Fortunately it was just a dream. You\'re okay, right?'}],phrases:[{id:'Cerita dong!',en:'Tell me! / Go on, tell the story!',ctx:'Encouraging someone to share — warm and curious'},{id:'Lalu apa yang terjadi?',en:'Then what happened?',ctx:'Classic story-listener response'},{id:'Tiba-tiba saja...',en:'All of a sudden... / Out of nowhere...',ctx:'Dramatic story-telling opener'},{id:'Singkat cerita...',en:'In short... / Long story short...',ctx:'To summarize a long story — very natural'},{id:'Pada akhirnya...',en:'In the end... / Ultimately...',ctx:'Closing a story or argument'},{id:'Tidak kusangka!',en:'I didn\'t expect it! / Who would have thought!',ctx:'Expressing genuine surprise — sangka = to expect/think'},{id:'Untungnya...',en:'Fortunately... / Luckily...',ctx:'untungnya = luckily — useful for relief after a problem'},{id:'Panjang ceritanya.',en:'It\'s a long story.',ctx:'When you don\'t want to explain everything'}],reading:{text:'Pertama kali saya naik pesawat, saya sangat gugup. Saya belum pernah terbang sebelumnya. Ketika pesawat mulai bergerak, jantung saya berdegup kencang. Lalu tiba-tiba pesawat sudah di udara! Saya melihat ke luar jendela dan melihat awan putih. Akhirnya saya merasa tenang dan bahkan tertidur di pesawat.',translation:'The first time I took a plane, I was very nervous. I had never flown before. When the plane started moving, my heart was beating fast. Then suddenly the plane was in the air! I looked out the window and saw white clouds. In the end I felt calm and even fell asleep on the plane.',questions:[{q:'Bagaimana perasaan penulis sebelum naik pesawat?',a:'Sangat gugup',hint:'How did the writer feel?'},{q:'Apa yang terjadi ketika pesawat bergerak?',a:'Jantungnya berdegup kencang',hint:'What happened to his/her heart?'},{q:'Apa yang penulis lakukan di pesawat akhirnya?',a:'Tertidur',hint:'What did the writer do on the plane in the end?'}]},exercises:[{type:'fill',prompt:'Pertama saya di kantor, ___ ada masalah komputer. (First I was at the office, then suddenly a computer problem came up)',ans:'tiba-tiba',hint:'The phrase for \'suddenly\''},{type:'fill',prompt:'Lalu apa yang ___? (Then what happened?)',ans:'terjadi',hint:'The verb \'to happen\''},{type:'order',words:['cerita','dong!','Cerita'],ans:'Cerita dong!',en:'Tell me the story!'},{type:'fill',prompt:'___ cerita, saya berhasil! (In the end, I succeeded!)',ans:'Akhir',hint:'First word of \'akhirnya\' (in the end)'}]},
25:{dialogue:[{sp:'A',id:'Menurut kamu, mana lebih baik — kerja kantoran atau kerja sendiri?',en:'In your opinion, which is better — office work or working for yourself?'},{sp:'B',id:'Menurut saya, kerja sendiri lebih bebas. Tapi risikonya lebih besar.',en:'In my opinion, working for yourself is freer. But the risks are greater.'},{sp:'A',id:'Saya setuju soal risiko. Tapi kerja kantoran kadang terlalu membosankan.',en:'I agree about the risk. But office work is sometimes too boring.'},{sp:'B',id:'Betul juga. Masing-masing punya kelebihan dan kekurangan.',en:'That\'s true too. Each has its advantages and disadvantages.'},{sp:'A',id:'Saya pikir yang terpenting adalah melakukan apa yang kita sukai.',en:'I think the most important thing is doing what we enjoy.'},{sp:'B',id:'Setuju banget! Kalau suka pekerjaannya, lebih mudah bersemangat.',en:'Totally agree! If you enjoy your work, it\'s easier to stay motivated.'}],phrases:[{id:'Menurut saya, yang terbaik adalah...',en:'In my opinion, the best is...',ctx:'Giving a recommendation or conclusion'},{id:'Ada benarnya juga.',en:'There\'s some truth to that too.',ctx:'Acknowledging someone\'s point without fully agreeing'},{id:'Saya kurang setuju.',en:'I somewhat disagree.',ctx:'Softer disagreement — kurang = less, so \'less agree\''},{id:'Dari sudut pandang saya...',en:'From my point of view...',ctx:'sudut pandang = perspective/point of view — formal'},{id:'Kelebihan dan kekurangannya...',en:'The advantages and disadvantages...',ctx:'kelebihan = advantage, kekurangan = disadvantage/shortage'},{id:'Yang terpenting adalah...',en:'The most important thing is...',ctx:'terpenting = most important — strong conclusion opener'},{id:'Saya ragu tentang itu.',en:'I\'m uncertain about that.',ctx:'ragu = uncertain/doubtful — useful for nuanced opinions'},{id:'Pada dasarnya, saya setuju.',en:'Basically, I agree.',ctx:'pada dasarnya = basically/fundamentally — sophisticated opener'}],reading:{text:'Indonesia adalah negara demokrasi terbesar keempat di dunia. Setiap lima tahun, rakyat memilih presiden dan wakil rakyat mereka. Pemilihan umum di Indonesia dikenal cukup damai dan teratur. Namun, masih ada tantangan seperti korupsi dan ketimpangan pembangunan. Banyak anak muda Indonesia kini aktif bersuara tentang isu-isu sosial lewat media sosial.',translation:'Indonesia is the world\'s fourth largest democracy. Every five years, the people choose their president and representatives. General elections in Indonesia are known to be quite peaceful and orderly. However, there are still challenges such as corruption and development inequality. Many young Indonesians are now actively speaking out about social issues through social media.',questions:[{q:'Indonesia adalah demokrasi terbesar keberapa?',a:'Keempat di dunia',hint:'Which ranking?'},{q:'Seberapa sering Indonesia mengadakan pemilu?',a:'Setiap lima tahun',hint:'How often are elections held?'},{q:'Bagaimana anak muda menyuarakan pendapat mereka?',a:'Lewat media sosial',hint:'How do young people speak out?'}]},exercises:[{type:'fill',prompt:'Ada ___ juga dengan pendapat kamu. (There is some truth to your opinion)',ans:'benarnya',hint:'\'truth of it\' — the noun form with -nya'},{type:'fill',prompt:'Saya ___ tentang hal itu. (I\'m uncertain about that)',ans:'ragu',hint:'The adjective meaning uncertain/doubtful'},{type:'order',words:['adalah','Yang','belajar','terpenting'],ans:'Yang terpenting adalah belajar',en:'The most important thing is to learn'},{type:'fill',prompt:'Dari sudut ___ saya... (From my point of view...)',ans:'pandang',hint:'Second word of \'point of view\''}]},
26:{dialogue:[{sp:'A',id:'Kamu sudah baca artikel tentang Nusantara?',en:'Have you read the article about Nusantara?'},{sp:'B',id:'Belum. Tentang apa?',en:'Not yet. What\'s it about?'},{sp:'A',id:'Tentang ibu kota baru Indonesia. Sangat menarik!',en:'About Indonesia\'s new capital. Very interesting!'},{sp:'B',id:'Oh iya, saya tahu! Proyek ambisius sekali.',en:'Oh yes, I know! Such an ambitious project.'},{sp:'A',id:'Menurut kamu, apakah ini keputusan yang tepat?',en:'In your opinion, is this the right decision?'},{sp:'B',id:'Sulit dinilai sekarang. Kita lihat saja perkembangannya.',en:'Hard to judge now. Let\'s just see how it develops.'}],phrases:[{id:'Kamu sudah baca tentang...?',en:'Have you read about...?',ctx:'Natural way to start a news-based conversation'},{id:'Menarik sekali beritanya!',en:'The news is very interesting!',ctx:'Sharing excitement about something you\'ve read'},{id:'Saya setuju dengan pendapat itu.',en:'I agree with that opinion.',ctx:'Formal agreement in discussion'},{id:'Kita lihat saja.',en:'Let\'s just wait and see.',ctx:'Patient, non-committal response — very Indonesian'},{id:'Perlu dikaji lebih lanjut.',en:'It needs to be studied further.',ctx:'Thoughtful response — dikaji = studied/examined'},{id:'Berita ini viral!',en:'This news is going viral!',ctx:'Describing trending news — viral is used the same way'},{id:'Jangan percaya berita hoaks!',en:'Don\'t believe fake news!',ctx:'hoaks = hoax — a borrowed word everyone uses'},{id:'Cek dulu sumbernya.',en:'Check the source first.',ctx:'Media literacy phrase — very relevant in digital age'}],reading:{text:'Media sosial menjadi bagian penting dari kehidupan orang Indonesia. Instagram, TikTok, dan Twitter sangat populer di kalangan anak muda. Banyak kreator konten Indonesia yang sudah terkenal di tingkat internasional. Namun, media sosial juga membawa tantangan seperti penyebaran hoaks dan ujaran kebencian. Literasi digital menjadi keterampilan yang semakin penting di era ini.',translation:'Social media has become an important part of Indonesian life. Instagram, TikTok, and Twitter are very popular among young people. Many Indonesian content creators are already internationally famous. However, social media also brings challenges such as the spread of hoaxes and hate speech. Digital literacy is becoming an increasingly important skill in this era.',questions:[{q:'Media sosial apa yang populer di Indonesia?',a:'Instagram, TikTok, dan Twitter',hint:'Three platforms mentioned'},{q:'Apa tantangan dari media sosial?',a:'Penyebaran hoaks dan ujaran kebencian',hint:'Two challenges mentioned'},{q:'Apa keterampilan yang semakin penting?',a:'Literasi digital',hint:'What skill is becoming more important?'}]},exercises:[{type:'fill',prompt:'Kita ___ saja perkembangannya. (Let\'s just see how it develops)',ans:'lihat',hint:'The verb \'to see/watch\''},{type:'fill',prompt:'Jangan percaya berita ___! (Don\'t believe fake news!)',ans:'hoaks',hint:'Borrowed English word'},{type:'order',words:['sumbernya','Cek','dulu'],ans:'Cek dulu sumbernya',en:'Check the source first'},{type:'fill',prompt:'Berita ini ___ banget! (This news is so viral!)',ans:'viral',hint:'Same word as in English'}]},
27:{dialogue:[{sp:'A',id:'Selamat malam! Ada meja untuk dua orang?',en:'Good evening! Is there a table for two?'},{sp:'B',id:'Ada, silakan duduk di pojok sana.',en:'Yes, please sit in that corner.'},{sp:'A',id:'Terima kasih. Boleh minta menunya?',en:'Thank you. May I have the menu?'},{sp:'B',id:'Ini menunya. Mau pesan minuman dulu?',en:'Here is the menu. Would you like to order drinks first?'},{sp:'A',id:'Iya, satu es jeruk dan satu air mineral ya.',en:'Yes, one iced orange juice and one mineral water.'},{sp:'B',id:'Baik, saya kembali sebentar lagi untuk ambil pesanan makanan.',en:'Okay, I\'ll be back shortly to take your food order.'}],phrases:[{id:'Silakan duduk.',en:'Please sit down.',ctx:'silakan = please (inviting someone) — very polite'},{id:'Mau pesan apa?',en:'What would you like to order?',ctx:'Standard waiter/waitress opener'},{id:'Rekomendasinya apa?',en:'What is your recommendation?',ctx:'Asking a waiter what\'s best — always get great answers!'},{id:'Satu porsi, ya.',en:'One serving, please.',ctx:'porsi = portion/serving — standard ordering word'},{id:'Sudah termasuk pajak?',en:'Is tax already included?',ctx:'pajak = tax — good to know at restaurants'},{id:'Pisah atau jadi satu bon?',en:'Separate or one bill?',ctx:'Splitting the bill — common question among friends dining'},{id:'Pelayanannya sangat baik.',en:'The service is very good.',ctx:'pelayanan = service — useful for feedback'},{id:'Kami akan kembali!',en:'We will come back!',ctx:'Highest compliment to a restaurant'}],reading:{text:'Restoran Padang adalah salah satu jenis restoran paling ikonik di Indonesia. Ciri khasnya adalah cara penyajian makanan — belasan piring kecil berisi berbagai lauk ditaruh di meja sekaligus. Kamu hanya membayar untuk apa yang kamu makan. Masakan Padang terkenal dengan cita rasa yang kaya rempah dan pedas. Rendang, gulai, dan dendeng adalah beberapa menu andalannya.',translation:'Padang restaurants are one of the most iconic types of restaurants in Indonesia. Their hallmark is the way food is served — dozens of small plates containing various dishes are placed on the table all at once. You only pay for what you eat. Padang cuisine is famous for its rich spiced and spicy flavours. Rendang, gulai, and dendeng are some of its signature dishes.',questions:[{q:'Apa ciri khas restoran Padang?',a:'Belasan piring kecil ditaruh di meja sekaligus',hint:'How is food served?'},{q:'Di restoran Padang, kamu bayar untuk apa?',a:'Hanya untuk apa yang kamu makan',hint:'What do you pay for?'},{q:'Sebutkan tiga menu andalan masakan Padang!',a:'Rendang, gulai, dan dendeng',hint:'Three dishes are mentioned'}]},exercises:[{type:'fill',prompt:'___ duduk di sini. (Please sit here)',ans:'Silakan',hint:'The polite invitation word'},{type:'fill',prompt:'Rekomendasinya ___? (What is your recommendation?)',ans:'apa',hint:'The question word \'what\''},{type:'order',words:['satu','bon?','atau','Pisah','jadi'],ans:'Pisah atau jadi satu bon?',en:'Separate or one bill?'},{type:'fill',prompt:'___ sangat baik di sini! (The service is very good here!)',ans:'Pelayanannya',hint:'The noun for \'service\' + -nya'}]},
28:{dialogue:[{sp:'A',id:'Tidak terasa, sudah hampir satu bulan belajar!',en:'Time flies, it\'s almost been one month of studying!'},{sp:'B',id:'Iya! Kamu sudah berkembang pesat sekali.',en:'Yes! You\'ve developed so quickly.'},{sp:'A',id:'Masih banyak yang perlu saya tingkatkan.',en:'There\'s still a lot I need to improve.'},{sp:'B',id:'Bagian mana yang paling sulit buat kamu?',en:'Which part is the most difficult for you?'},{sp:'A',id:'Mendengarkan orang bicara cepat masih susah.',en:'Listening to people speaking fast is still difficult.'},{sp:'B',id:'Normal itu! Teruslah berlatih dan jangan menyerah!',en:'That\'s normal! Keep practicing and don\'t give up!'}],phrases:[{id:'Tidak terasa waktu berlalu.',en:'Time passes without noticing.',ctx:'Expressing that time has flown by — very poetic'},{id:'Saya sudah berkembang pesat.',en:'I\'ve developed rapidly.',ctx:'pesat = rapid/fast (for growth) — great self-affirmation'},{id:'Masih perlu banyak latihan.',en:'I still need a lot of practice.',ctx:'Humble acknowledgment of ongoing improvement'},{id:'Jangan menyerah!',en:'Don\'t give up!',ctx:'menyerah = to give up — strong encouragement'},{id:'Sedikit demi sedikit.',en:'Little by little.',ctx:'Expressing gradual progress — very encouraging'},{id:'Konsistensi adalah kunci.',en:'Consistency is the key.',ctx:'kunci = key — applies to language learning perfectly'},{id:'Saya bangga bisa sampai di sini.',en:'I\'m proud to have gotten this far.',ctx:'Celebrating progress — very important to acknowledge'},{id:'Mulai besok saya akan lebih giat.',en:'Starting tomorrow I will be more diligent.',ctx:'giat = diligent/hardworking — a positive resolution'}],reading:{text:'Belajar bahasa baru membutuhkan waktu dan ketekunan. Tidak ada jalan pintas. Tapi setiap hari yang dilewati dengan belajar adalah investasi untuk diri sendiri. Kesalahan adalah bagian dari proses — jangan takut salah. Setiap penutur asli pun pernah melewati fase kebingungan. Yang terpenting adalah terus bergerak maju dan tidak berhenti.',translation:'Learning a new language requires time and perseverance. There are no shortcuts. But every day spent studying is an investment in yourself. Mistakes are part of the process — don\'t be afraid of making mistakes. Every native speaker also went through a phase of confusion. The most important thing is to keep moving forward and not stop.',questions:[{q:'Apa yang dibutuhkan untuk belajar bahasa baru?',a:'Waktu dan ketekunan',hint:'What two things are needed?'},{q:'Mengapa kita tidak perlu takut salah?',a:'Karena kesalahan adalah bagian dari proses',hint:'Why shouldn\'t we fear mistakes?'},{q:'Apa hal terpenting dalam belajar bahasa?',a:'Terus bergerak maju dan tidak berhenti',hint:'What is most important?'}]},exercises:[{type:'fill',prompt:'Tidak ___ waktu berlalu! (Time passes without noticing!)',ans:'terasa',hint:'The verb \'to be felt/sensed\''},{type:'fill',prompt:'Jangan ___! Kamu pasti bisa! (Don\'t give up! You can do it!)',ans:'menyerah',hint:'The verb \'to give up\''},{type:'order',words:['demi','Sedikit','sedikit'],ans:'Sedikit demi sedikit',en:'Little by little'},{type:'fill',prompt:'___ adalah kunci! (Consistency is the key!)',ans:'Konsistensi',hint:'The noun for consistency'}]},
29:{dialogue:[{sp:'A',id:'Satu bulan lalu saya tidak bisa bicara Bahasa Indonesia sama sekali.',en:'One month ago I couldn\'t speak Indonesian at all.'},{sp:'B',id:'Dan sekarang kamu bisa! Luar biasa sekali perkembanganmu!',en:'And now you can! Your progress is truly extraordinary!'},{sp:'A',id:'Terima kasih untuk semua dukungannya.',en:'Thank you for all the support.'},{sp:'B',id:'Kamu yang kerja keras! Saya hanya membantu sedikit.',en:'You worked hard! I only helped a little.'},{sp:'A',id:'Sekarang saya mau cari teman bicara orang Indonesia asli.',en:'Now I want to find an Indonesian native speaker to talk with.'},{sp:'B',id:'Bagus! Coba iTalki atau Tandem. Mereka pasti senang membantu!',en:'Great! Try iTalki or Tandem. They\'ll definitely be happy to help!'}],phrases:[{id:'Sama sekali tidak bisa.',en:'Cannot at all / Completely unable.',ctx:'sama sekali = at all — used with negations for emphasis'},{id:'Perkembanganmu luar biasa!',en:'Your progress is extraordinary!',ctx:'Genuine, specific praise — more meaningful than \'bagus\''},{id:'Terima kasih atas dukungannya.',en:'Thank you for the support.',ctx:'atas = for/over (in gratitude) — formal and warm'},{id:'Saya mau mencari teman bicara.',en:'I want to find a speaking partner.',ctx:'teman bicara = conversation partner — practical learning goal'},{id:'Bahasa Indonesia membuka banyak pintu.',en:'Indonesian opens many doors.',ctx:'Motivational — pintu = door, both literal and figurative'},{id:'Saya percaya diri sekarang.',en:'I am confident now.',ctx:'percaya diri = self-confident — literally \'believe in self\''},{id:'Perjalanan masih panjang.',en:'The journey is still long.',ctx:'Acknowledging ongoing growth with humility'},{id:'Saya tidak akan berhenti belajar.',en:'I will not stop learning.',ctx:'Strong commitment to continued learning'}],reading:{text:'Setelah dua puluh sembilan hari belajar, saya bisa merasakan perubahan nyata. Dulu saya tidak mengerti kata-kata di layar ponsel berbahasa Indonesia. Sekarang saya bisa membaca berita pendek dan mengerti sebagian besar isinya. Berbicara masih perlu latihan lebih banyak. Tapi yang terpenting, saya tidak takut lagi untuk mencoba. Bahasa adalah jembatan menuju dunia baru.',translation:'After twenty-nine days of studying, I can feel a real change. Before I didn\'t understand words on Indonesian-language phone screens. Now I can read short news and understand most of the content. Speaking still needs more practice. But the most important thing is I\'m no longer afraid to try. Language is a bridge to a new world.',questions:[{q:'Apa perubahan nyata yang dirasakan?',a:'Bisa membaca berita dan mengerti sebagian besar isinya',hint:'What real change is felt?'},{q:'Apa yang masih perlu banyak latihan?',a:'Berbicara',hint:'What still needs more practice?'},{q:'Bahasa diibaratkan sebagai apa?',a:'Jembatan menuju dunia baru',hint:'What is language compared to?'}]},exercises:[{type:'fill',prompt:'Sama ___ tidak bisa! (Cannot at all!)',ans:'sekali',hint:'Second word of \'at all\''},{type:'fill',prompt:'Saya ___ diri sekarang. (I am confident now)',ans:'percaya',hint:'First word of \'self-confident\''},{type:'order',words:['pintu','banyak','membuka','Bahasa'],ans:'Bahasa membuka banyak pintu',en:'Language opens many doors'},{type:'fill',prompt:'Terima kasih ___ semua dukungannya. (Thank you for all the support)',ans:'atas',hint:'The preposition \'for/over\' in gratitude'}]},
30:{dialogue:[{sp:'A',id:'Halo semuanya! Hari ini adalah hari ketiga puluh!',en:'Hello everyone! Today is day thirty!'},{sp:'B',id:'Selamat! Kamu sudah menyelesaikan perjalanan 30 hari!',en:'Congratulations! You\'ve completed the 30-day journey!'},{sp:'A',id:'Tidak terasa ya! Saya belajar begitu banyak hal.',en:'Time flew by! I\'ve learned so many things.'},{sp:'B',id:'Sekarang kamu sudah bisa berbicara Bahasa Indonesia!',en:'Now you can already speak Indonesian!'},{sp:'A',id:'Masih perlu banyak belajar. Tapi saya tidak menyerah!',en:'Still need to learn a lot. But I won\'t give up!'},{sp:'B',id:'Semangat terus! Bahasa Indonesia menunggumu! Selamat!',en:'Keep the spirit! Indonesian is waiting for you! Congratulations!'}],phrases:[{id:'Selamat atas pencapaianmu!',en:'Congratulations on your achievement!',ctx:'atas = on/over (for praise), pencapaian = achievement'},{id:'Kamu luar biasa!',en:'You are extraordinary!',ctx:'The warmest compliment — luar biasa literally = outside normal'},{id:'Teruslah belajar dan berkembang.',en:'Keep learning and growing.',ctx:'A beautiful send-off for a language learner'},{id:'Saya siap berbicara dengan penutur asli!',en:'I\'m ready to speak with native speakers!',ctx:'penutur asli = native speaker — your next goal'},{id:'Terima kasih atas perjalanan ini.',en:'Thank you for this journey.',ctx:'Grateful reflection on the whole experience'},{id:'Ini bukan akhir, ini adalah awal.',en:'This is not the end, this is the beginning.',ctx:'The perfect closing thought'},{id:'Bahasa Indonesia menunggumu!',en:'Indonesian is waiting for you!',ctx:'Encouraging — menunggu = to wait'},{id:'Sampai jumpa di Indonesia!',en:'See you in Indonesia!',ctx:'The ultimate motivation — plan that trip!'}],reading:{text:'Tiga puluh hari yang luar biasa telah berlalu. Dari tidak bisa mengucapkan satu kata pun, kini kamu mampu bercakap-cakap dalam Bahasa Indonesia. Ini bukan akhir dari perjalanan — ini hanyalah awal. Indonesia menunggu dengan segala keindahan alamnya, keragaman budayanya, dan kehangatan penduduknya. Teruslah berlatih, teruslah tumbuh, dan suatu hari kamu akan berdiri di tanah Indonesia dan berkata: \'Saya bisa berbicara Bahasa Indonesia!\'',translation:'Thirty extraordinary days have passed. From not being able to utter a single word, now you are able to have conversations in Indonesian. This is not the end of the journey — this is only the beginning. Indonesia awaits with all its natural beauty, cultural diversity, and the warmth of its people. Keep practicing, keep growing, and one day you will stand on Indonesian soil and say: \'I can speak Indonesian!\'',questions:[{q:'Apa perubahan setelah 30 hari?',a:'Dari tidak bisa, kini bisa bercakap-cakap',hint:'What changed in 30 days?'},{q:'Apa yang Indonesia tawarkan?',a:'Keindahan alam, keragaman budaya, kehangatan penduduk',hint:'Three things Indonesia offers'},{q:'Apa yang akan kamu katakan saat berdiri di Indonesia?',a:'Saya bisa berbicara Bahasa Indonesia!',hint:'The dream sentence — what will you say?'}]},exercises:[{type:'fill',prompt:'Selamat atas ___mu! (Congratulations on your achievement!)',ans:'pencapaian',hint:'The noun for achievement'},{type:'fill',prompt:'Teruslah belajar dan ___. (Keep learning and growing)',ans:'berkembang',hint:'The verb \'to grow/develop\''},{type:'order',words:['akhir','bukan','ini','Ini','adalah','awal.'],ans:'Ini bukan akhir, ini adalah awal.',en:'This is not the end, this is the beginning.'},{type:'fill',prompt:'Sampai jumpa di ___! (See you in Indonesia!)',ans:'Indonesia',hint:'The destination that awaits you!'}]}
};

